import{_ as e,c as p,a as n,b as t,d as l,r as o,o as c}from"./app-DxT-J_20.js";const i={};function r(u,s){const a=o("DateMeta");return c(),p("div",null,[s[0]||(s[0]=n("h1",{id:"_13-fpl-2",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#_13-fpl-2"},[n("span",null,"13. FPL (2)")])],-1)),t(a),s[1]||(s[1]=l(`<h2 id="common-lisp" tabindex="-1"><a class="header-anchor" href="#common-lisp"><span>Common Lisp</span></a></h2><ul><li>Common Lisp는 1980년대 초반 여러 Lisp 방언(dialect)의 특징을 통합하여 만들어진 대형 언어임</li><li>Scheme이 작고 간결한 철학을 지닌 언어인 것과 달리, Common Lisp은 풍부한 기능과 복잡성을 가진 언어</li><li>Features include: <ul><li>Records</li><li>Arrays</li><li>Complex numbers</li><li>Character strings</li><li>Powerful I/O capabilities</li><li>Iterative control statements</li></ul></li></ul><p><strong>DEFSTRUCT를 사용한 RECORDS</strong></p><ul><li>DEFSTRUCT는 구조체를 만드는 명령어</li></ul><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">DEFSTRUCT</span> PERSON</span>
<span class="line">  NAME</span>
<span class="line">  AGE<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">SETF</span> P1 <span class="token punctuation">(</span><span class="token car">MAKE-PERSON</span> <span class="token lisp-property property">:NAME</span> <span class="token string">&quot;ALICE&quot;</span> <span class="token lisp-property property">:AGE</span> <span class="token number">30</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">PERSON-NAME</span> P1<span class="token punctuation">)</span> <span class="token comment">; → &quot;ALICE&quot;</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">PERSON-AGE</span> P1<span class="token punctuation">)</span>  <span class="token comment">; → 30</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>MAKE-PERSON</code>은 <code>:NAME</code>과 <code>:AGE</code>를 받아서 구조체 객체를 생성, 그 결과를 변수 P1에 할당함</li><li>P1 구조체에서 NAME 슬롯을 꺼냄. 결과는 &quot;ALICE&quot;가 됨</li></ul><p><strong>MAKE-ARRAY를 사용한 배열</strong></p><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">SETF</span> A <span class="token punctuation">(</span><span class="token car">MAKE-ARRAY</span> <span class="token punctuation">&#39;(</span><span class="token number">2</span> <span class="token number">3</span><span class="token punctuation">)</span> <span class="token lisp-property property">:INITIAL-CONTENTS</span> <span class="token punctuation">&#39;(</span><span class="token punctuation">(</span><span class="token number">1</span> <span class="token number">2</span> <span class="token number">3</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token number">4</span> <span class="token number">5</span> <span class="token number">6</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">AREF</span> A <span class="token number">0</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token comment">; → 2</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>2x3짜리 2차원 배열 A를 만들고, 초기값으로 <code>((1 2 3) (4 5 6))</code>을 설정</li><li><code>AREF</code>는 배열의 특정 위치 값을 꺼낼 때 사용하는 함수</li><li>위에서는 0행 1열의 값을 꺼내니 2가 나옴</li></ul><p><strong>COMPLEX NUMBERS</strong></p><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">SETF</span> C #C<span class="token punctuation">(</span><span class="token number">3</span> <span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">REALPART</span> C<span class="token punctuation">)</span> <span class="token comment">; → 3</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">IMAGPART</span> C<span class="token punctuation">)</span> <span class="token comment">; → 4</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">ABS</span> C<span class="token punctuation">)</span>      <span class="token comment">; → 5.0</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>#C(3 4)</code>는 복소수 3 + 4i를 표현하는 방법</li><li><code>REALPART</code>: 실수부만 꺼냄</li><li><code>IMAGPART</code>: 허수부만 꺼냄</li><li><code>ABS</code>: 복소수의 크기를 계산 (√(3² + 4²) = 5.0)</li></ul><p><strong>문자열(String)</strong></p><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">SETF</span> S <span class="token string">&quot;<span class="token argument">HELLO</span>, LISP!&quot;</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">SUBSEQ</span> S <span class="token number">0</span> <span class="token number">5</span><span class="token punctuation">)</span> <span class="token comment">; → &quot;HELLO&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>문자열 변수 S를 정의</li><li><code>SUBSEQ</code>는 부분 문자열을 자를 때 사용 (0부터 5 전까지)</li></ul><p><strong>파일 입출력 (I/O)</strong></p><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">WITH-OPEN-FILE</span> <span class="token punctuation">(</span><span class="token car">STREAM</span> <span class="token string">&quot;<span class="token argument">OUTPUT</span>.TXT&quot;</span> <span class="token lisp-property property">:DIRECTION</span> <span class="token lisp-property property">:OUTPUT</span> <span class="token lisp-property property">:IF-EXISTS</span> <span class="token lisp-property property">:SUPERSEDE</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">(</span><span class="token car">FORMAT</span> STREAM <span class="token string">&quot;<span class="token argument">HELLO</span>, FILE!~%&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>&quot;OUTPUT.TXT&quot;</code>라는 파일을 쓰기 모드로 열어서, &quot;HELLO, FILE!&quot;이라는 문장을 씀</li><li><code>WITH-OPEN-FILE</code>은 파일을 열고 닫는 것을 자동으로 처리</li><li><code>STREAM</code>은 파일 스트림(입출력 통로)을 나타내는 변수명</li><li><code>:DIRECTION :OUTPUT</code> → 파일을 쓰기 모드로 연다는 뜻</li><li><code>:IF-EXISTS :SUPERSEDE</code> → 파일이 이미 있으면 덮어쓴다(기존 내용 삭제)는 의미</li></ul><p><strong>반복문: LOOP</strong></p><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">LOOP</span> FOR I FROM <span class="token number">1</span> TO <span class="token number">5</span> DO</span>
<span class="line">  <span class="token punctuation">(</span><span class="token car">FORMAT</span> T <span class="token string">&quot;<span class="token argument">I</span> = ~A~%&quot;</span> I<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>FOR I FROM 1 TO 5</code>는 1부터 5까지 반복</li><li>각 반복마다 <code>I = 1</code>, <code>I = 2</code>, ... 를 출력</li><li><code>~A</code>는 값을 자동으로 문자열로 변환해 출력함</li><li><code>T</code>는 출력 대상을 콘솔(터미널)로</li><li>Common LISP allows both static and dynamic scoping <ul><li>The default scoping for variables is static</li><li>Declaring a variable to be &quot;special,&quot; that variable becomes dynamically scoped</li></ul></li></ul><p><strong>Function</strong></p><p><code>(DEFUN *functionname* (*param1 param2 ... paramN*) (*statements*))</code></p><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">DEFUN</span> square <span class="token punctuation">(</span><span class="token car">x</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token car">*</span> x x<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">DEFUN</span> iterative_member <span class="token punctuation">(</span><span class="token car">atm</span> lst<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">(</span><span class="token car">PROG</span> <span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    loop_1</span>
<span class="line">    <span class="token punctuation">(</span><span class="token car">COND</span></span>
<span class="line">      <span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token car">NULL</span> lst<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token car">RETURN</span> NIL<span class="token punctuation">)</span><span class="token punctuation">)</span>      <span class="token comment">; 리스트 끝 → 못 찾음</span></span>
<span class="line">      <span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token car">EQUAL</span> atm <span class="token punctuation">(</span><span class="token car">CAR</span> lst<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token car">RETURN</span> T<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">; 찾음 → TRUE</span></span>
<span class="line">    <span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">(</span><span class="token car">SETQ</span> lst <span class="token punctuation">(</span><span class="token car">CDR</span> lst<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment">; 리스트 다음 요소로 이동</span></span>
<span class="line">    <span class="token punctuation">(</span><span class="token car">GO</span> loop_1<span class="token punctuation">)</span>           <span class="token comment">; 다시 반복</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">DEFUN</span> recursive_member <span class="token punctuation">(</span><span class="token car">atm</span> lst<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">(</span><span class="token car">COND</span></span>
<span class="line">    <span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token car">NULL</span> lst<span class="token punctuation">)</span> NIL<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token car">EQUAL</span> atm <span class="token punctuation">(</span><span class="token car">CAR</span> lst<span class="token punctuation">)</span><span class="token punctuation">)</span> T<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">(</span><span class="token car">T</span> <span class="token punctuation">(</span><span class="token car">recursive_member</span> atm <span class="token punctuation">(</span><span class="token car">CDR</span> lst<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>PROG</code>: 내부에 레이블(label)을 정의하고, 코드 실행 흐름을 제어할 수 있는 구조. 간단한 루프나 점프(비추천)를 만들 때 사용</li><li><code>GO</code>: PROG 내에서 정의한 레이블로 점프함</li><li><code>RETURN</code>: PROG 블록에서 값을 반환하며 탈출</li></ul><p><strong>Backquote operator (<code>\`</code>)</strong></p><ul><li>Similar to the Scheme&#39;s QUOTE, except that some parts of the parameter can be unquoted by preceding them with commas</li><li>Common Lisp에서는 <code>,</code>(쉼표)를 이용해서 일부 표현식을 &quot;평가 가능하게 만들 수 있다&quot;는 게 큰 특징 <ul><li><code>\`(a (* 3 4) c)</code> evaluates to <code>(a (* 3 4) c)</code></li><li><code>\`(a ,(* 3 4) c)</code> evaluates to <code>(a 12 c)</code></li><li><code>,(* 3 4)</code> → <code>(* 3 4)</code> 부분만 계산됨</li></ul></li></ul><p><strong>Macros</strong></p><ul><li>Macros are often used in Common LISP to extend the language <ul><li>매크로는 코드 조각을 생성하거나 바꿔주는 도구</li><li>일반 함수와 달리, 매크로는 &quot;코드를 반환하는 함수&quot;처럼 동작함</li></ul></li><li>Create their effect in two steps: <ul><li>확장 (Expansion) – 코드가 매크로 정의대로 치환됨</li><li>평가 (Evaluation) – 확장된 코드가 실행됨</li></ul></li><li>Lisp 코드를 확장하고 제어 구조를 새로 정의할 수 있음</li></ul><p>새로운 언어 기능처럼 만들 수 있어서 언어를 확장하는 도구로 사용됨</p><ul><li>Some of the predefined functions of Common Lisp are actually macros. <ul><li>일부 Common Lisp의 기본 제어문들도 사실은 함수가 아니라 매크로임</li><li>i.e. <code>DOTIMES</code>(주어진 횟수만큼 반복), <code>DOLIST</code>(리스트를 반복), <code>DO</code></li></ul></li><li>Users can define their own macros with <code>DEFMACRO</code> (사용자 정의 매크로)</li></ul><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token defun"><span class="token keyword">defun</span> <span class="token function">say-hello</span> <span class="token punctuation">(</span><span class="token arguments"><span class="token argument variable">x</span></span><span class="token punctuation">)</span></span></span>
<span class="line">  <span class="token punctuation">(</span><span class="token car">dotimes</span> <span class="token punctuation">(</span><span class="token car">i</span> x <span class="token quoted-symbol variable symbol">&#39;Stop!</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">(</span><span class="token car">format</span> <span class="token boolean">t</span> <span class="token string">&quot;~% Hello ~s&quot;</span> i<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">say-hello</span> <span class="token number">3</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">; Hello 0</span></span>
<span class="line"><span class="token comment">; Hello 1</span></span>
<span class="line"><span class="token comment">; ...</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Common Lisp Symbol Data Type</strong></p><ul><li>Common Lisp has a symbol data type (similar to that of Ruby) <ul><li>심볼(symbol)은 Lisp에서 이름(name)을 표현하는 데이터 타입</li><li>The reserved words are symbols that evaluate to themselves (i.e. T and NIL)</li><li>Symbols are either bound or unbound</li><li>Bound → 심볼이 어떤 값에 바인딩(연결) 되어 있음</li><li>Unbound → 심볼이 아직 어떤 값에도 바인딩되지 않음 (에러 발생 가능)</li></ul></li></ul><div class="language-lisp line-numbers-mode" data-highlighter="prismjs" data-ext="lisp"><pre><code class="language-lisp"><span class="line"><span class="token punctuation">(</span><span class="token car">DEFUN</span> EXAMPLE <span class="token punctuation">(</span><span class="token car">X</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">(</span><span class="token car">+</span> X <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">(</span><span class="token car">SETF</span> A <span class="token number">10</span><span class="token punctuation">)</span>  <span class="token comment">; A는 10에 바인딩됨</span></span>
<span class="line">B            <span class="token comment">; 아무런 바인딩이 없으면 → 에러: unbound variable B</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>함수 인자 → 함수 실행 중 바인딩</li><li><code>SETF</code>, <code>LET</code> 등으로 값 할당된 변수 → 바인딩됨</li><li>아무 할당도 없는 일반 심볼 → 바인딩되지 않음 → 에러 발생</li></ul><h2 id="ml" tabindex="-1"><a class="header-anchor" href="#ml"><span>ML</span></a></h2><p>A static-scoped functional language with syntax that is closer to Pascal than to Lisp</p><ul><li>ML은 Lisp 계열처럼 괄호로 가득한 문법이 아님</li></ul><p>타입 선언(type declarations) 가능하지만, 대부분은 자동으로 추론(type inferencing)됨</p><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">add</span> x y <span class="token operator">=</span> x <span class="token operator">+</span> y<span class="token punctuation">;</span> <span class="token comment">(* ML이 x와 y의 타입을 int로 추론 *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>It is strongly typed and has no type coercions <ul><li>타입 간 암묵적 변환(coercion)을 허용하지 않음</li><li>Type of every variable and expression can be statically determined</li></ul></li><li>Does not have imperative-style variables <ul><li>변수는 불변(immutable)이고, 새로운 값을 만들지 기존 값을 변경하지 않음</li></ul></li><li>Includes exception handling and a module facility for implementing abstract data types</li><li>Includes lists and list operations</li></ul><p><strong>ML Specifics</strong></p><p>A table called the evaluation environment stores the names of all identifiers in a program, along with their types (like a run-time symbol table)</p><p>평가 환경(evaluation environment)은 일종의 런타임 심볼 테이블</p><p>프로그램 내의 모든 식별자(identifier)에 대해 이름, 타입, (함수인 경우) 바디를 저장하고, 정적 스코프 규칙에 따라 평가할 때 사용됨</p><p><strong>Function declaration form</strong></p><p><code>fun name (formal parameters) = expression;</code></p><ul><li>Note that infix!</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">cube</span><span class="token punctuation">(</span>x <span class="token punctuation">:</span> <span class="token class-name">int</span><span class="token punctuation">)</span> <span class="token operator">=</span> x <span class="token operator">*</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token operator">*</span> <span class="token punctuation">[</span><span class="token keyword">In</span> Scheme<span class="token punctuation">]</span> <span class="token punctuation">(</span>DEFINE <span class="token punctuation">(</span>cube x<span class="token punctuation">)</span> <span class="token comment">(* x x x)) *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>x는 int 타입으로 명시됨</li><li>결과값은 마지막 표현식인 <code>x * x * x</code></li><li>함수의 반환값(return value)은 마지막 표현식의 값</li><li>Expression can be a list of expressions <ul><li>Separated by semicolons and surrounded by parentheses</li><li>Return value is from the last expression</li><li>Without side effect, expressions before the last serve no purpose!</li></ul></li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">test</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">(</span></span>
<span class="line">  print <span class="token string">&quot;ML is nice\\n&quot;</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token number">3</span> <span class="token operator">+</span> <span class="token number">4</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token number">11</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>여러 표현식을 한 줄에 쓸 수 있고, <code>;</code>로 구분하며 <code>()</code>로 감쌈</p><p>마지막 표현식 11이 이 함수의 반환값. ML은 순수 함수형 언어라, 부수 효과(side effect)가 없으면 앞의 표현식은 무시됨</p><p><strong>Type inference</strong></p><p>정적 타입 언어지만, 대부분의 경우 타입을 명시할 필요가 없음</p><p>왜냐하면 ML의 타입 추론 시스템이 문맥을 보고 타입을 자동으로 결정하기 때문</p><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">circumf</span><span class="token punctuation">(</span>r<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">3.14159</span> <span class="token operator">*</span> r <span class="token operator">*</span> r<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>Takes a floating-point and produces a floating-point result</li><li>Types are inferred from type of the literal in expression</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">square</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token operator">=</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>No literal and arithmetic operator (명확한 리터럴이 없을 경우, 연산자를 기준으로 추론)</li></ul><p>→ type of the parameter and the function are assumed to be numeric</p><ul><li>Default numeric type: int</li><li><code>square(2.75);</code> → cause an error (not coerce real) (square는 int -&gt; int)</li><li>→ <code>square_real(2.75);</code></li><li>The type could be attached to return value, as in:</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">square</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token punctuation">:</span> <span class="token class-name">real</span> <span class="token operator">=</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">square</span><span class="token punctuation">(</span>x<span class="token punctuation">:</span> <span class="token class-name">real</span><span class="token punctuation">)</span><span class="token punctuation">:</span> <span class="token class-name">real</span> <span class="token operator">=</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>여기서 <code>: real</code>은 함수 반환값의 타입을 지정한 것</li><li>With no type specified, it would default to int (the default for numeric values)</li><li>User-defined overloaded functions are not allowed, so if we wanted a cube function for real parameters, it would need to have a different name <ul><li>예: <code>fun square(x: int)</code>와 <code>fun square(x: real)</code>을 동시에 정의 불가 → 이름을 다르게 지어야 함</li></ul></li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">square_int</span><span class="token punctuation">(</span>x<span class="token punctuation">:</span> <span class="token class-name">int</span><span class="token punctuation">)</span> <span class="token operator">=</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">square_real</span><span class="token punctuation">(</span>x<span class="token punctuation">:</span> <span class="token class-name">real</span><span class="token punctuation">)</span> <span class="token operator">=</span> x <span class="token operator">*</span><span class="token punctuation">.</span> x<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">(* 다양한 위치에서의 타입 명시 *)</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">square</span><span class="token punctuation">(</span>x <span class="token punctuation">:</span> <span class="token class-name">real</span><span class="token punctuation">)</span> <span class="token operator">=</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">square</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">(</span>x <span class="token punctuation">:</span> <span class="token class-name">real</span><span class="token punctuation">)</span> <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">square</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token operator">=</span> x <span class="token operator">*</span> <span class="token punctuation">(</span>x <span class="token punctuation">:</span> <span class="token class-name">real</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>ML selection</strong></p><ul><li>Similar to that of the imperative languages</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">if</span> expression <span class="token keyword">then</span> then_expression</span>
<span class="line"><span class="token keyword">else</span> else_expression</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>where the first expression must evaluate to a Boolean value</p><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">fact</span><span class="token punctuation">(</span>n <span class="token punctuation">:</span> <span class="token class-name">int</span><span class="token punctuation">)</span><span class="token punctuation">:</span> <span class="token class-name">int</span> <span class="token operator">=</span> <span class="token keyword">if</span> n <span class="token operator">&lt;=</span> <span class="token number">1</span> <span class="token keyword">then</span> <span class="token number">1</span></span>
<span class="line">                         <span class="token keyword">else</span> n <span class="token operator">*</span> fact<span class="token punctuation">(</span>n − <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">(</span><span class="token operator">*</span> <span class="token punctuation">[</span><span class="token keyword">In</span> Scheme<span class="token punctuation">]</span></span>
<span class="line"><span class="token punctuation">(</span>DEFINE <span class="token punctuation">(</span>factorial n<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">(</span><span class="token keyword">IF</span> <span class="token punctuation">(</span><span class="token operator">&lt;=</span> n <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line">      <span class="token number">1</span></span>
<span class="line">      <span class="token comment">(* n (factorial (− n 1))))) *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Pattern matching is used to allow a function to operate on different parameter forms</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">fact</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line">  <span class="token operator">|</span> fact<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line">  <span class="token operator">|</span> fact<span class="token punctuation">(</span>n <span class="token punctuation">:</span> <span class="token class-name">int</span><span class="token punctuation">)</span> <span class="token punctuation">:</span> <span class="token class-name">int</span> <span class="token operator">=</span> n <span class="token operator">*</span> fact<span class="token punctuation">(</span>n – <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Lists</strong></p><ul><li>Literal lists are specified in brackets <ul><li><code>[3, 5, 7]</code></li><li><code>[]</code>: the empty list</li></ul></li><li>CONS: binary infix operator <code>::</code><ul><li>앞에 원소를 붙여서 새로운 리스트를 만드는 이항 연산자</li><li><code>4 :: [3, 5, 7]</code>, which evaluates to <code>[4, 3, 5, 7]</code></li><li>right-associative: <code>1 :: 2 :: 3 :: []</code>는 <code>1 :: (2 :: (3 :: []))</code></li></ul></li><li>CAR is the unary operator <code>hd</code><ul><li>리스트의 첫 번째 원소를 반환, 빈 리스트에는 직접 적용X</li><li><code>hd [3, 5, 7]</code> → <code>3</code></li></ul></li><li>CDR is the unary operator <code>tl</code><ul><li>리스트의 나머지 리스트를 반환 (첫 원소 제외), 빈 리스트에는 직접 적용X</li><li><code>tl [3, 5, 7]</code> → <code>[5, 7]</code></li></ul></li><li>Availability of patterned function parameters → <code>hd</code> and <code>tl</code> are much less frequently used in ML than CAR and CDR in Scheme</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">length</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line">  <span class="token operator">|</span> length<span class="token punctuation">(</span>h <span class="token operator">::</span> t<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">1</span> <span class="token operator">+</span> length<span class="token punctuation">(</span>t<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">append</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">,</span> lis2<span class="token punctuation">)</span> <span class="token operator">=</span> lis2</span>
<span class="line">  <span class="token operator">|</span> append<span class="token punctuation">(</span>h <span class="token operator">::</span> t<span class="token punctuation">,</span> lis2<span class="token punctuation">)</span> <span class="token operator">=</span> h <span class="token operator">::</span> append<span class="token punctuation">(</span>t<span class="token punctuation">,</span> lis2<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">(* [In Scheme]</span>
<span class="line">(DEFINE (length list)</span>
<span class="line">  (COND</span>
<span class="line">    ((NULL? list) 0)</span>
<span class="line">    (ELSE (+ 1 (length (CDR list))))))</span>
<span class="line"></span>
<span class="line">(DEFINE (append list1 list2)</span>
<span class="line">  (COND</span>
<span class="line">    ((NULL? list1) list2)</span>
<span class="line">    (ELSE (CONS (CAR list1)</span>
<span class="line">                (append (CDR list1) list2))))) *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>ML의 패턴 매칭 덕분에 <code>hd</code>, <code>tl</code> 같은 연산자가 함수 정의 내부에서 구조적으로 녹아들어 있음</li></ul><p><strong>val statement</strong></p><ul><li>The <code>val</code> statement binds a name to a value (similar to <code>DEFINE</code> in Scheme)</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">val</span> distance <span class="token operator">=</span> time <span class="token operator">*</span> speed<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>As is the case with <code>DEFINE</code>, <code>val</code> is nothing like an assignment statement in an imperative language → name cannot be later rebound to a new value</li><li>If there are two val statements for the same identifier, the first is hidden by the second</li></ul><p><code>val</code> statements are often used in <code>let</code> constructs (지역 변수 블록을 만드는 표현식)</p><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">let</span></span>
<span class="line">  <span class="token keyword">val</span> radius <span class="token operator">=</span> <span class="token number">2.7</span></span>
<span class="line">  <span class="token keyword">val</span> pi <span class="token operator">=</span> <span class="token number">3.14159</span></span>
<span class="line"><span class="token keyword">in</span></span>
<span class="line">  pi <span class="token operator">*</span> radius <span class="token operator">*</span> radius</span>
<span class="line"><span class="token keyword">end</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">(</span><span class="token operator">*</span> <span class="token punctuation">[</span><span class="token keyword">In</span> Scheme<span class="token punctuation">]</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token keyword">LET</span> <span class="token punctuation">(</span><span class="token punctuation">(</span>radius <span class="token number">2.7</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>pi <span class="token number">3.14159</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">     <span class="token comment">(* pi radius radius)) *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>filter</strong></p><p>A higher-order filtering function for lists</p><p>리스트에서 조건을 만족하는 원소만 남기는 고차 함수</p><ul><li>Takes a predicate function as its parameter, often in the form of a lambda expression</li></ul><p><code>fn(parameter) =&gt; expression</code></p><ul><li>Lambda expressions are defined like functions, except with the reserved word <code>fn</code></li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line">filter<span class="token punctuation">(</span><span class="token keyword">fn</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> x <span class="token operator">&lt;</span> <span class="token number">100</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">25</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">711</span><span class="token punctuation">,</span> <span class="token number">50</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">(* This returns [25, 1, 50] *)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">(* 일반함수도 사용 가능 *)</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">isSmall</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span> <span class="token operator">=</span> x <span class="token operator">&lt;</span> <span class="token number">100</span><span class="token punctuation">;</span></span>
<span class="line">filter<span class="token punctuation">(</span>isSmall<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">25</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">711</span><span class="token punctuation">,</span> <span class="token number">50</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>map</strong></p><p>A higher-order function that takes a single parameter, a function</p><p>리스트의 각 원소에 함수를 적용해서 새로운 리스트를 만드는 고차 함수</p><ul><li>Applies the parameter function to each element of a list and returns a list of results</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">cube</span> x <span class="token operator">=</span> x <span class="token operator">*</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">val</span> cubeList <span class="token operator">=</span> map cube<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">val</span> newList <span class="token operator">=</span> cubeList <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">(* This sets newList to [1, 27, 125] *)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">(* Alternative: use a lambda expression *)</span></span>
<span class="line"><span class="token keyword">val</span> newList <span class="token operator">=</span> map <span class="token punctuation">(</span><span class="token keyword">fn</span> x <span class="token operator">=&gt;</span> x <span class="token operator">*</span> x <span class="token operator">*</span> x<span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Function Composition</strong></p><p>두 함수를 결합하여 새로운 함수를 만드는 것</p><ul><li>Use the unary operator, <code>o</code> (a lowercase &quot;oh&quot;)</li></ul><p><code>val h = g o f;</code></p><ul><li>First applies function <code>f</code> and then applies function <code>g</code> to the returned value from <code>f</code></li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">double</span> x <span class="token operator">=</span> <span class="token number">2</span> <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">square</span> x <span class="token operator">=</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">val</span> doubleThenSquare <span class="token operator">=</span> square o double<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">val</span> result <span class="token operator">=</span> doubleThenSquare<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">(* 결과: square(double(3)) = square(6) = 36 *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Currying</strong></p><ul><li>ML functions actually take just one parameter</li><li>If more, it considers the parameters a tuple (commas required)</li></ul><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">addTuple</span> <span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span> <span class="token operator">=</span> a <span class="token operator">+</span> b<span class="token punctuation">;</span> <span class="token comment">(* tuple 인자 *)</span></span>
<span class="line">addTuple<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">(* OK *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Currying: Replaces a function with more than one parameter (여러 인자를 받는 함수를, 하나의 인자만 받는 함수들의 연속으로 바꾸는 방식)</li></ul><p>→ a function with one parameter that returns a function that takes the other parameters of the original function</p><ul><li>Can be defined in curried form by leaving out the commas in the parameters</li></ul><p>쉼표 없이 인자를 나열하면 자동으로 커링된 함수가 정의됨</p><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">add</span> a b <span class="token operator">=</span> a <span class="token operator">+</span> b<span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">(* → fun add a = fn b =&gt; a + b; *)</span></span>
<span class="line"><span class="token comment">(* add는 먼저 a를 받고, 그 결과로 b를 받는 함수를 반환 *)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">val</span> result <span class="token operator">=</span> add <span class="token number">3</span> <span class="token number">5</span><span class="token punctuation">;</span>   <span class="token comment">(* = 8 *)</span></span>
<span class="line"><span class="token keyword">val</span> add3 <span class="token operator">=</span> add <span class="token number">3</span><span class="token punctuation">;</span>       <span class="token comment">(* = fn b =&gt; 3 + b *)</span></span>
<span class="line"><span class="token keyword">val</span> r <span class="token operator">=</span> add3 <span class="token number">10</span><span class="token punctuation">;</span>        <span class="token comment">(* = 13 *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Tuple vs Curried Form</li></ul><table><thead><tr><th>형식</th><th>정의</th><th>호출 방식</th></tr></thead><tbody><tr><td>Tuple 인자</td><td><code>fun f (a, b) = ...</code></td><td><code>f(3, 4)</code></td></tr><tr><td>Curried 인자</td><td><code>fun f a b = ...</code></td><td><code>f 3 4</code></td></tr></tbody></table><p>커링을 쓰면 부분 적용이 가능해서 유용함</p><p><strong>Partial Evaluation (부분 평가)</strong></p><ul><li>Curried functions can be used to create new functions by partial evaluation</li><li>Partial evaluation means that the function is evaluated with actual parameters for one or more of the leftmost actual parameters</li></ul><p>부분 평가는 함수의 일부 인자만 먼저 적용해서 새로운 함수를 만드는 방식</p><p>특히 커링된 함수에서 왼쪽부터 일부 인자에만 값을 주면, 그 값이 고정된 새로운 함수가 반환</p><div class="language-sml line-numbers-mode" data-highlighter="prismjs" data-ext="sml"><pre><code class="language-sml"><span class="line"><span class="token keyword">fun</span> <span class="token function">add</span> a b <span class="token operator">=</span> a <span class="token operator">+</span> b<span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">fun</span> <span class="token function">add5</span> x <span class="token operator">=</span> add <span class="token number">5</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">(* Takes the actual parameter 5 and evaluates the add function with 5 as the value of its first formal parameter. *)</span></span>
<span class="line"><span class="token comment">(* Returns a function that adds 5 to its single parameter *)</span></span>
<span class="line"><span class="token keyword">val</span> num <span class="token operator">=</span> add5 <span class="token number">10</span><span class="token punctuation">;</span> <span class="token comment">(* sets num to 15 *)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">(* [In Scheme]</span>
<span class="line">(DEFINE (add x y) (+ x y))</span>
<span class="line">[Curried version]</span>
<span class="line">(DEFINE (add y) (LAMBDA (x) (+ y x)))</span>
<span class="line">((add 3) 4) *)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>커링 + partial evaluation을 이용하면, 재사용 가능한 특화 함수를 쉽게 만들 수 있음</p><h2 id="haskell" tabindex="-1"><a class="header-anchor" href="#haskell"><span>Haskell</span></a></h2><ul><li>Similar to ML: Syntax, static scoped, strongly typed, type inferencing, pattern matching</li></ul><table><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>문법 (Syntax)</td><td>함수 중심 문법 구조가 비슷함</td></tr><tr><td>정적 스코프 (Static scoping)</td><td>변수 바인딩은 정의된 위치 기준으로 결정</td></tr><tr><td>강한 타입 (Strong typing)</td><td>타입이 명확하고, 잘못된 타입 사용은 컴파일 에러</td></tr><tr><td>타입 추론 (Type inferencing)</td><td>명시하지 않아도 대부분 타입을 자동으로 추론</td></tr><tr><td>패턴 매칭 (Pattern matching)</td><td>리스트, 튜플, 데이터 타입 등에서 쉽게 분해 가능</td></tr></tbody></table><ul><li>Different from ML (and most other functional languages):</li></ul><table><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>함수 오버로딩 가능</td><td>ML에서는 사용자 정의 함수의 오버로딩이 불가능하지만, Haskell은 type class를 통해 오버로딩 지원</td></tr><tr><td>Nonstrict semantics (지연 평가)</td><td>인자가 실제로 사용될 때까지 계산되지 않음 (lazy evaluation)</td></tr><tr><td>순수 함수형 언어 (Purely functional)</td><td>변수 없음, 대입문 없음, 부수 효과 없음 → 모든 함수는 입력만으로 결과가 결정됨</td></tr></tbody></table><p>e.g., no variables, no assignment statements, and no side effects of any kind</p><table><thead><tr><th></th><th>ML</th><th>Haskell</th></tr></thead><tbody><tr><td>변수 선언</td><td><code>val x = 3;</code></td><td><code>x = 3</code></td></tr><tr><td>바인딩 특성</td><td>변수 x는 변경 불가이지만, val을 반복해서 새 이름 지정 가능</td><td>x는 상수처럼 취급됨 (변경 불가), <code>=</code>는 수학적 정의로 사용됨 (대입 아님)</td></tr></tbody></table><p><strong>Basic operations</strong></p><ul><li><code>head</code>: 0th element</li><li><code>head [2, 3, 4]</code> -- <code>2</code></li><li><code>tail</code>: All elements except element 0</li><li><code>tail [2, 3, 4]</code> -- <code>[3, 4]</code></li><li><code>init</code>: all elements except the last element (initial part of a list)</li><li><code>init [2, 3, 4]</code> -- <code>[2, 3]</code></li><li><code>last</code>: last element</li><li><code>last [2, 3, 4]</code> -- <code>4</code></li><li><code>take</code>: get elements from front</li><li><code>take 2 [2, 3, 4]</code> -- <code>[2, 3]</code></li><li><code>drop</code>: remove elements from front</li><li><code>drop 2 [2, 3, 4]</code> -- <code>[4]</code></li></ul><p><code>head</code>, <code>tail</code>, <code>init</code>, <code>last</code>는 빈 리스트 <code>[]</code>에 사용하면 에러가 발생. 예: <code>head []</code> → runtime error</p><p><code>take</code>과 <code>drop</code>은 길이를 넘는 값을 넣어도 안전함.</p><ul><li><code>take 5 [1, 2]</code> → <code>[1, 2]</code></li><li><code>drop 5 [1, 2]</code> → <code>[]</code></li><li>Indexing from 0 using <code>!!</code><ul><li>n번째 인덱스에 있는 값을 반환: <code>list !! index</code></li></ul></li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span> <span class="token operator">!!</span> <span class="token number">1</span>   <span class="token comment">-- 2</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span> <span class="token operator">!!</span> <span class="token number">2</span>   <span class="token comment">-- 3</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span> <span class="token operator">!!</span> <span class="token number">0</span> <span class="token comment">-- 1</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span> <span class="token operator">!!</span> <span class="token number">5</span>      <span class="token comment">-- 에러: index too large</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span> <span class="token operator">!!</span> <span class="token punctuation">(</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>   <span class="token comment">-- 에러: negative index</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Haskell Lists</strong></p><ul><li>List notation: put elements in brackets (리스트는 동일한 타입의 값들로 구성)</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">directions</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;north&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;south&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;east&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;west&quot;</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token hvariable">directions</span> <span class="token comment">-- 결과: 4</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Arithmetic series with the <code>..</code> operator (산술 수열) <ul><li>첫 번째 두 항목을 기반으로 증가 간격을 추정</li><li><code>[2, 4..10]</code> is <code>[2, 4, 6, 8, 10]</code></li><li>무한 리스트도 생성 가능</li><li><code>[1,3..]</code> -- 무한히 2씩 증가하는 수열</li><li><code>take 5 [1,3..]</code> -- <code>[1,3,5,7,9]</code></li></ul></li><li>Concatenation is with <code>++</code> (리스트 연결) <ul><li><code>[1, 3] ++ [5, 7]</code> results in <code>[1, 3, 5, 7]</code></li><li>시간 복잡도는 앞 리스트의 길이에 비례하므로 앞쪽 리스트가 너무 길면 성능 저하 가능</li></ul></li><li>CONS, CAR, CDR via the colon operator (infix version of CONS) <ul><li><code>1:[3, 5, 7]</code> results in <code>[1, 3, 5, 7]</code></li></ul></li></ul><p>A list can only contain the same type</p><ul><li>예: <code>[1, 2, 3]</code>은 OK, 하지만 <code>[1, &quot;two&quot;, 3]</code>은 타입 오류</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">product</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>  <span class="token comment">-- 120</span></span>
<span class="line"><span class="token builtin">sum</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>      <span class="token comment">-- 15</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>   <span class="token comment">-- 5</span></span>
<span class="line"><span class="token builtin">reverse</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span>     <span class="token comment">-- [4, 3, 2, 1]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>product</code>, <code>sum</code>은 Num 타입 클래스의 인스턴스(예: Int, Integer, Float 등)에만 적용 가능</li><li><code>reverse</code>는 어떤 타입의 리스트에도 동작. (예: <code>reverse &quot;hello&quot;</code> → <code>&quot;olleh&quot;</code>)</li></ul><p><strong>Haskell Tuples</strong></p><p>A tuple can contain the different type</p><ul><li>이질성: 튜플은 각 원소가 서로 다른 타입일 수 있음</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token punctuation">(</span><span class="token constant">False</span><span class="token punctuation">,</span> <span class="token char string">&#39;a&#39;</span><span class="token punctuation">,</span> <span class="token constant">True</span><span class="token punctuation">)</span>    <span class="token comment">-- (Bool, Char, Bool)</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token constant">True</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token char string">&#39;a&#39;</span><span class="token punctuation">,</span> <span class="token char string">&#39;b&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>    <span class="token comment">-- (Bool, [Char]) 또는 (Bool, String)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>쌍(pair), 즉 두 원소짜리 튜플에 대해서 편리한 접근 함수</p><ul><li><code>fst</code>: 두 원소짜리 튜플의 첫 번째 원소를 반환</li><li><code>snd</code>: 두 원소짜리 튜플의 두 번째 원소를 반환</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">fst</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&quot;Hello&quot;</span><span class="token punctuation">)</span>        <span class="token comment">-- 1</span></span>
<span class="line"><span class="token builtin">snd</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&quot;Hello&quot;</span><span class="token punctuation">)</span>        <span class="token comment">-- &quot;Hello&quot;</span></span>
<span class="line"><span class="token builtin">fst</span> <span class="token punctuation">(</span><span class="token builtin">snd</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span>   <span class="token comment">-- 2</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Haskell Functions</strong></p><ul><li>Haskell에서는 괄호 없이 공백으로 함수 인자를 전달</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">f</span> <span class="token hvariable">x</span>         <span class="token comment">-- f(x)</span></span>
<span class="line"><span class="token hvariable">f</span> <span class="token hvariable">x</span> <span class="token hvariable">y</span>       <span class="token comment">-- f(x, y) → 실제로는 ((f x) y) 형태로 왼쪽부터 적용</span></span>
<span class="line"><span class="token hvariable">f</span> <span class="token punctuation">(</span><span class="token hvariable">g</span> <span class="token hvariable">x</span><span class="token punctuation">)</span>     <span class="token comment">-- f(g(x))</span></span>
<span class="line"><span class="token hvariable">f</span> <span class="token hvariable">x</span> <span class="token punctuation">(</span><span class="token hvariable">g</span> <span class="token hvariable">y</span><span class="token punctuation">)</span>   <span class="token comment">-- f(x, g(y))</span></span>
<span class="line"><span class="token hvariable">f</span> <span class="token hvariable">x</span> <span class="token operator">*</span> <span class="token hvariable">g</span> <span class="token hvariable">y</span>   <span class="token comment">-- f(x) * g(y) ← *가 f x와 g y 결과를 곱함</span></span>
<span class="line"></span>
<span class="line"><span class="token hvariable">double</span> <span class="token hvariable">x</span> <span class="token operator">=</span> <span class="token hvariable">x</span> <span class="token operator">+</span> <span class="token hvariable">x</span></span>
<span class="line"><span class="token hvariable">quadruple</span> <span class="token hvariable">x</span> <span class="token operator">=</span> <span class="token hvariable">double</span> <span class="token punctuation">(</span><span class="token hvariable">double</span> <span class="token hvariable">x</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token builtin">take</span> <span class="token punctuation">(</span><span class="token hvariable">double</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">]</span>  <span class="token comment">-- [1, 2, 3, 4]</span></span>
<span class="line"><span class="token hvariable">avg</span> <span class="token hvariable">ns</span> <span class="token operator">=</span> <span class="token builtin">sum</span> <span class="token hvariable">ns</span> <span class="token operator">\`div\`</span> <span class="token builtin">length</span> <span class="token hvariable">ns</span>      <span class="token comment">-- average</span></span>
<span class="line"><span class="token comment">-- Function surrounded by backticks: infix binary operator</span></span>
<span class="line"><span class="token comment">-- avg ns = div (sum ns) (length ns)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Because Haskell support polymorphism, this works for any numeric type of x</li></ul><p>아래 함수는 구체적인 타입 명시 없이 정의됐지만, Haskell의 타입 추론과 다형성 지원 덕분에, x가 Num 타입 클래스에 속한 어떤 타입이든 사용할 수 있음</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">square</span> <span class="token hvariable">x</span> <span class="token operator">=</span> <span class="token hvariable">x</span> <span class="token operator">*</span> <span class="token hvariable">x</span></span>
<span class="line"><span class="token comment">-- [In ML]</span></span>
<span class="line"><span class="token comment">-- fun cube(x : int) = x * x * x;</span></span>
<span class="line"><span class="token comment">-- ML에서는 구체적인 타입 필요</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Syntax differences from ML</li></ul><table><thead><tr><th>항목</th><th>Haskell</th><th>ML (Standard ML)</th></tr></thead><tbody><tr><td>함수 정의 시작 키워드</td><td>없음 (직접 이름으로 시작)</td><td><code>fun</code> 사용 필요</td></tr><tr><td>패턴 매칭</td><td>각 정의를 별도 줄로 작성 (직관적)</td><td>\`</td></tr><tr><td>함수 이름 반복</td><td>줄마다 함수 이름 다시 작성</td><td>하나의 함수 정의 내에서 이름을 반복하지 않음</td></tr></tbody></table><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">fact</span> <span class="token number">0</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line"><span class="token hvariable">fact</span> <span class="token number">1</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line"><span class="token hvariable">fact</span> <span class="token hvariable">n</span> <span class="token operator">=</span> <span class="token hvariable">n</span> <span class="token operator">*</span> <span class="token hvariable">fact</span> <span class="token punctuation">(</span><span class="token hvariable">n</span> – <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token hvariable">fib</span> <span class="token number">0</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line"><span class="token hvariable">fib</span> <span class="token number">1</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line"><span class="token hvariable">fib</span> <span class="token punctuation">(</span><span class="token hvariable">n</span> <span class="token operator">+</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">fib</span> <span class="token punctuation">(</span><span class="token hvariable">n</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span> <span class="token operator">+</span> <span class="token hvariable">fib</span> <span class="token hvariable">n</span></span>
<span class="line"><span class="token comment">-- 수식 기반 패턴 매칭: 이 표현은 Haskell에서만 가능</span></span>
<span class="line"><span class="token comment">-- n + 2는 패턴 매칭 시 역으로 &quot;2 이상&quot;을 의미함</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">{- [In ML]</span>
<span class="line">fun fact(0) = 1</span>
<span class="line">  | fact(1) = 1</span>
<span class="line">  | fact(n : int) : int = n * fact(n – 1)</span>
<span class="line"></span>
<span class="line">fun fib(0) = 1</span>
<span class="line">  | fact(1) = 1</span>
<span class="line">  | fact(n : int) : int = fact(n – 1) * fact(n – 2)</span>
<span class="line">-- ML은 정수 연산 표현식 기반 패턴은 허용하지 않음</span>
<span class="line">-- 즉, fib(n + 2) 같은 형태는 사용 불가 -}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Guards can be added to lines of a function definition to specify the circumstances under which the definition can be applied <ul><li><code>|</code> (파이프) 기호를 사용해 조건을 나열함</li><li>각 조건이 True가 되면 해당 결과를 반환</li><li>An <code>otherwise</code> can appear as the last condition in a conditional expression</li><li>마지막에 <code>otherwise</code>를 써서 기본(default) 조건을 지정할 수 있음</li><li>(<code>otherwise</code>는 사실 True로 정의된 상수)</li></ul></li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">fact</span> <span class="token hvariable">n</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">==</span> <span class="token number">0</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">==</span> <span class="token number">1</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">&gt;</span> <span class="token number">0</span>  <span class="token operator">=</span> <span class="token hvariable">n</span> <span class="token operator">*</span> <span class="token hvariable">fact</span><span class="token punctuation">(</span><span class="token hvariable">n</span> – <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token hvariable">sub</span> <span class="token hvariable">n</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">&lt;</span> <span class="token number">10</span>    <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">&gt;</span> <span class="token number">100</span>   <span class="token operator">=</span> <span class="token number">2</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token builtin">otherwise</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>if-then-else는 하나의 조건만 다루지만 guards는 여러 조건을 깔끔하게 나열할 수 있음</p><p><strong>Pattern Parameters</strong></p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token comment">-- product: 재귀적으로 곱셈 수행</span></span>
<span class="line"><span class="token builtin">product</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line"><span class="token builtin">product</span> <span class="token punctuation">(</span><span class="token hvariable">a</span><span class="token operator">:</span><span class="token hvariable">x</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">a</span> <span class="token operator">*</span> <span class="token builtin">product</span> <span class="token hvariable">x</span></span>
<span class="line"><span class="token comment">-- length</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token punctuation">(</span><span class="token hvariable">a</span><span class="token operator">:</span><span class="token hvariable">x</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">1</span> <span class="token operator">+</span> <span class="token builtin">length</span> <span class="token hvariable">x</span></span>
<span class="line"><span class="token comment">-- reverse</span></span>
<span class="line"><span class="token builtin">reverse</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">reverse</span> <span class="token punctuation">(</span><span class="token hvariable">a</span><span class="token operator">:</span><span class="token hvariable">x</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token builtin">reverse</span><span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token punctuation">)</span> <span class="token operator">++</span> <span class="token punctuation">[</span><span class="token hvariable">a</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- Factorial:</span></span>
<span class="line"><span class="token hvariable">fact</span> <span class="token hvariable">n</span> <span class="token operator">=</span> <span class="token builtin">product</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">..</span><span class="token hvariable">n</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- drop: 리스트에서 앞에서부터 n개를 제거</span></span>
<span class="line"><span class="token builtin">drop</span> <span class="token number">0</span> <span class="token hvariable">x</span> <span class="token operator">=</span> <span class="token hvariable">x</span></span>
<span class="line"><span class="token builtin">drop</span> <span class="token hvariable">_</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">drop</span> <span class="token hvariable">n</span> <span class="token punctuation">(</span><span class="token hvariable">a</span><span class="token operator">:</span><span class="token hvariable">x</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token builtin">drop</span> <span class="token punctuation">(</span><span class="token hvariable">n</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token hvariable">x</span></span>
<span class="line"><span class="token comment">-- ++: 리스트 연결 연산을 직접 정의한 것</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">++</span> <span class="token hvariable">y</span> <span class="token operator">=</span> <span class="token hvariable">y</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token hvariable">a</span><span class="token operator">:</span><span class="token hvariable">x</span><span class="token punctuation">)</span> <span class="token operator">++</span> <span class="token hvariable">y</span> <span class="token operator">=</span> <span class="token hvariable">a</span> <span class="token operator">:</span> <span class="token punctuation">(</span><span class="token hvariable">x</span> <span class="token operator">++</span> <span class="token hvariable">y</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">-- *: 자연수에 대한 곱셈을 재귀적으로 정의한 것</span></span>
<span class="line"><span class="token hvariable">m</span> <span class="token operator">*</span> <span class="token number">0</span> <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line"><span class="token hvariable">m</span> <span class="token operator">*</span> <span class="token hvariable">n</span> <span class="token operator">=</span> <span class="token hvariable">m</span> <span class="token operator">+</span> <span class="token punctuation">(</span><span class="token hvariable">m</span> <span class="token operator">*</span> <span class="token punctuation">(</span><span class="token hvariable">n</span> <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>let ... in construct</strong></p><ul><li>Similar to ML&#39;s let and val</li></ul><p><code>let &lt;바인딩들&gt; in &lt;표현식&gt;</code></p><p><code>let</code> 안에서는 여러 개의 지역 변수(또는 함수)를 정의할 수 있고, <code>in</code> 뒤에는 실제로 계산할 표현식을 적음</p><p>모든 <code>let</code> 내부 바인딩은 immutable(불변)</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">quadratic_root</span> <span class="token hvariable">a</span> <span class="token hvariable">b</span> <span class="token hvariable">c</span> <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">let</span></span>
<span class="line">    <span class="token hvariable">minus_b_over_2a</span>    <span class="token operator">=</span> − <span class="token hvariable">b</span> <span class="token operator">/</span> <span class="token punctuation">(</span><span class="token number">2.0</span> <span class="token operator">*</span> <span class="token hvariable">a</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token hvariable">root_part_over_2a</span>  <span class="token operator">=</span> <span class="token builtin">sqrt</span><span class="token punctuation">(</span><span class="token hvariable">b</span> <span class="token operator">^</span> <span class="token number">2</span> − <span class="token number">4.0</span> <span class="token operator">*</span> <span class="token hvariable">a</span> <span class="token operator">*</span> <span class="token hvariable">c</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token punctuation">(</span><span class="token number">2.0</span> <span class="token operator">*</span> <span class="token hvariable">a</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">in</span></span>
<span class="line">    <span class="token hvariable">minus_b_over_2a</span> − <span class="token hvariable">root_part_over_2a</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token hvariable">minus_b_over_2a</span> <span class="token operator">+</span> <span class="token hvariable">root_part_over_2a</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>항목</th><th>Haskell</th><th>ML (SML)</th></tr></thead><tbody><tr><td>시작 키워드</td><td><code>let</code></td><td><code>let</code> + 각 줄에 <code>val</code></td></tr><tr><td>종료 키워드</td><td><code>in</code> 이후 바로 결과 표현</td><td><code>in ... end</code> 블록으로 명확히 끝냄</td></tr></tbody></table><p><strong>where construct</strong></p><p>함수 본문 아래에 지역 변수를 정의하는 방식</p><p>여러 표현식에서 공통으로 쓰이는 중간 결과를 깔끔하게 정리할 수 있음</p><p><code>let ... in</code>은 표현식 내부, <code>where</code>는 함수 정의 바깥에 위치</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">quadratic_root</span> <span class="token hvariable">a</span> <span class="token hvariable">b</span> <span class="token hvariable">c</span> <span class="token operator">=</span></span>
<span class="line">  <span class="token punctuation">[</span><span class="token hvariable">minus_b_over_2a</span> <span class="token operator">-</span> <span class="token hvariable">root_part_over_2a</span><span class="token punctuation">,</span></span>
<span class="line">   <span class="token hvariable">minus_b_over_2a</span> <span class="token operator">+</span> <span class="token hvariable">root_part_over_2a</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token keyword">where</span></span>
<span class="line">    <span class="token hvariable">minus_b_over_2a</span>   <span class="token operator">=</span> <span class="token operator">-</span> <span class="token hvariable">b</span> <span class="token operator">/</span> <span class="token punctuation">(</span><span class="token number">2.0</span> <span class="token operator">*</span> <span class="token hvariable">a</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token hvariable">root_part_over_2a</span> <span class="token operator">=</span> <span class="token builtin">sqrt</span> <span class="token punctuation">(</span><span class="token hvariable">b</span> <span class="token operator">^</span> <span class="token number">2</span> <span class="token operator">-</span> <span class="token number">4.0</span> <span class="token operator">*</span> <span class="token hvariable">a</span> <span class="token operator">*</span> <span class="token hvariable">c</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token punctuation">(</span><span class="token number">2.0</span> <span class="token operator">*</span> <span class="token hvariable">a</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>항목</th><th><code>let ... in</code></th><th><code>where</code> 구문</th></tr></thead><tbody><tr><td>위치</td><td>표현식 내부</td><td>함수 정의 아래</td></tr><tr><td>문법 구조</td><td><code>let &lt;바인딩&gt; in &lt;표현식&gt;</code></td><td><code>&lt;표현식&gt; where &lt;바인딩&gt;</code></td></tr><tr><td>스코프</td><td><code>in</code> 뒤 표현식 안에서만 유효</td><td>해당 함수 정의 전체에서 유효</td></tr><tr><td>사용 예시</td><td><code>let x = ... in x + 1</code></td><td><code>f x = x + y where y = 3</code></td></tr></tbody></table><p><strong>List Comprehensions</strong></p><ul><li>Python의 리스트 내포와 비슷하지만, Haskell 특유의 표현력과 수학적인 문법을 잘 보여주는 기능</li></ul><p><code>[&lt;expression&gt; | &lt;qualifiers&gt;]</code></p><ul><li><code>&lt;expression&gt;</code>: 결과로 만들어질 각 원소</li><li><code>&lt;qualifiers&gt;</code>: 변수 생성, 조건 필터링 등</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token punctuation">[</span><span class="token hvariable">n</span> <span class="token operator">*</span> <span class="token hvariable">n</span> <span class="token operator">*</span> <span class="token hvariable">n</span> <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">..</span><span class="token number">50</span><span class="token punctuation">]</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- &quot;a list of all n*n*n such that n is taken from the range of 1 to 50&quot;</span></span>
<span class="line"><span class="token comment">-- The qualifier in this example has the form of a generator (n &lt;- [1..50])</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Multiple generators</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token punctuation">[</span><span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token punctuation">,</span> <span class="token hvariable">y</span><span class="token punctuation">)</span> <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">..</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token hvariable">y</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">4</span><span class="token operator">..</span><span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- [(1,4),(1,5),(2,4),(2,5),(3,4),(3,5)]</span></span>
<span class="line"><span class="token comment">-- x는 1부터 3까지, y는 4부터 5까지 → 모든 조합</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Dependant generator</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token punctuation">[</span><span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token punctuation">,</span> <span class="token hvariable">y</span><span class="token punctuation">)</span> <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">..</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token hvariable">y</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token hvariable">x</span> <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- [(1,2),(2,3),(3,4)]</span></span>
<span class="line"><span class="token comment">-- y는 x에 의존해서 결정됨</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>concat 정의 (리스트 평탄화)</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">concat</span> <span class="token hvariable">xss</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">x</span> <span class="token operator">|</span> <span class="token hvariable">xs</span> <span class="token operator">&lt;-</span> <span class="token hvariable">xss</span><span class="token punctuation">,</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token hvariable">xs</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">concat</span> <span class="token punctuation">[</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">6</span><span class="token punctuation">]</span><span class="token punctuation">]</span>  <span class="token comment">-- [1,2,3,4,5,6]</span></span>
<span class="line"><span class="token comment">-- 외부 리스트 xss에서 리스트 xs를 하나씩 꺼내고, 각 xs 안의 원소 x를 꺼내 리스트로 만듦</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>조건 필터(guard)</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token punctuation">[</span><span class="token hvariable">x</span> <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">..</span><span class="token hvariable">n</span><span class="token punctuation">]</span><span class="token punctuation">,</span> 조건식<span class="token punctuation">]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>It could be in the form of a test. If qualifiers are in the form of Boolean expressions (guards)</li></ul><p>약수 구하기 (factors)</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">factors</span> <span class="token hvariable">n</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">x</span> <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token operator">..</span><span class="token hvariable">n</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token hvariable">n</span> <span class="token operator">\`mod\`</span> <span class="token hvariable">x</span> <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- x가 1부터 n까지 순회하면서, n이 x로 나누어 떨어지면 (n mod x == 0) 리스트에 포함</span></span>
<span class="line"><span class="token hvariable">factors</span> <span class="token number">17</span>  <span class="token comment">-- [1,17]</span></span>
<span class="line"><span class="token hvariable">factors</span> <span class="token number">15</span>  <span class="token comment">-- [1,3,5,15]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>소수 판별 (prime)</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">prime</span> <span class="token hvariable">n</span> <span class="token operator">=</span> <span class="token hvariable">factors</span> <span class="token hvariable">n</span> <span class="token operator">==</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token hvariable">n</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- 소수는 오직 1과 자기 자신만 약수로 가지므로, factors n == [1, n]이면 소수</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>The backticks specify the function is used as a binary operator</li></ul><p><code>zip</code>: takes two lists and creates one list</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">zip</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span> <span class="token punctuation">[</span><span class="token char string">&#39;a&#39;</span><span class="token punctuation">,</span> <span class="token char string">&#39;b&#39;</span><span class="token punctuation">,</span> <span class="token char string">&#39;c&#39;</span><span class="token punctuation">,</span> <span class="token char string">&#39;d&#39;</span><span class="token punctuation">]</span>  <span class="token comment">-- [(1,&#39;a&#39;),(2,&#39;b&#39;),(3,&#39;c&#39;)]</span></span>
<span class="line"><span class="token comment">-- 두 리스트의 각 요소를 쌍으로 묶음. 더 짧은 리스트 기준으로 잘림</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>pairs</code> 함수: 인접 쌍 만들기</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">pairs</span> <span class="token hvariable">xs</span> <span class="token operator">=</span> <span class="token builtin">zip</span> <span class="token hvariable">xs</span> <span class="token punctuation">(</span><span class="token builtin">tail</span> <span class="token hvariable">xs</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token hvariable">pairs</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span>  <span class="token comment">-- [(1,2),(2,3),(3,4)]</span></span>
<span class="line"><span class="token comment">-- xs와 tail xs를 묶어서 (x₁,x₂), (x₂,x₃), ... 형태의 인접쌍 리스트 생성</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>sorted</code> 함수: 정렬 여부 검사</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">sorted</span> <span class="token operator">=</span> <span class="token builtin">and</span> <span class="token punctuation">[</span><span class="token hvariable">x</span> <span class="token operator">&lt;=</span> <span class="token hvariable">y</span> <span class="token operator">|</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token punctuation">,</span> <span class="token hvariable">y</span><span class="token punctuation">)</span> <span class="token operator">&lt;-</span> <span class="token hvariable">pairs</span> <span class="token hvariable">xs</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- pairs xs로 인접한 원소 쌍들을 만들고, x &lt;= y 조건을 검사하여 리스트 생성</span></span>
<span class="line"><span class="token comment">-- and는 그 리스트의 모든 값이 True인지 확인 (정렬 확인)</span></span>
<span class="line"><span class="token hvariable">sorted</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span>     <span class="token comment">-- True</span></span>
<span class="line"><span class="token hvariable">sorted</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span>  <span class="token comment">-- False</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>positions</code> 함수: 특정 값의 위치 찾기</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">positions</span> <span class="token hvariable">x</span> <span class="token hvariable">xs</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">i</span> <span class="token operator">|</span> <span class="token punctuation">(</span><span class="token hvariable">x&#39;</span><span class="token punctuation">,</span> <span class="token hvariable">i</span><span class="token punctuation">)</span> <span class="token operator">&lt;-</span> <span class="token builtin">zip</span> <span class="token hvariable">xs</span> <span class="token punctuation">[</span><span class="token number">0</span><span class="token operator">..</span><span class="token hvariable">n</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token hvariable">x</span> <span class="token operator">==</span> <span class="token hvariable">x&#39;</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token keyword">where</span> <span class="token hvariable">n</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token builtin">length</span> <span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">-</span> <span class="token number">1</span></span>
<span class="line"><span class="token comment">-- zip xs [0..n]을 통해 각 원소와 그 인덱스를 쌍으로 만듦</span></span>
<span class="line"><span class="token comment">-- 조건 x == x&#39;인 경우에만 인덱스 i를 결과 리스트에 포함</span></span>
<span class="line"><span class="token hvariable">positions</span> <span class="token number">0</span> <span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">]</span>  <span class="token comment">-- [0,2,7]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>String Comprehensions</strong></p><ul><li>String is list of characters. 문자열도 리스트 함수와 comprehension을 그대로 사용</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">zip</span> <span class="token string">&quot;abc&quot;</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span>         <span class="token comment">-- [(&#39;a&#39;,1),(&#39;b&#39;,2),(&#39;c&#39;,3)]</span></span>
<span class="line"><span class="token builtin">take</span> <span class="token number">3</span> <span class="token string">&quot;asdasd&quot;</span>             <span class="token comment">-- &quot;asd&quot;</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token string">&quot;adasd&quot;</span>              <span class="token comment">-- 5</span></span>
<span class="line"><span class="token punctuation">[</span><span class="token hvariable">c</span> <span class="token operator">|</span> <span class="token hvariable">c</span> <span class="token operator">&lt;-</span> <span class="token string">&quot;hello&quot;</span><span class="token punctuation">,</span> <span class="token hvariable">c</span> <span class="token operator">/=</span> <span class="token char string">&#39;l&#39;</span><span class="token punctuation">]</span> <span class="token comment">-- &quot;heo&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Quicksort</strong></p><p>리스트 내포(list comprehension)와 패턴 매칭을 활용해 아주 간결하게 표현</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">sort</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">sort</span> <span class="token punctuation">(</span><span class="token hvariable">h</span><span class="token operator">:</span><span class="token hvariable">t</span><span class="token punctuation">)</span> <span class="token operator">=</span></span>
<span class="line">  <span class="token builtin">sort</span> <span class="token punctuation">[</span><span class="token hvariable">b</span> <span class="token operator">|</span> <span class="token hvariable">b</span> <span class="token operator">&lt;-</span> <span class="token hvariable">t</span><span class="token punctuation">,</span> <span class="token hvariable">b</span> <span class="token operator">&lt;=</span> <span class="token hvariable">h</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">++</span> <span class="token punctuation">[</span><span class="token hvariable">h</span><span class="token punctuation">]</span> <span class="token operator">++</span></span>
<span class="line">  <span class="token builtin">sort</span> <span class="token punctuation">[</span><span class="token hvariable">b</span> <span class="token operator">|</span> <span class="token hvariable">b</span> <span class="token operator">&lt;-</span> <span class="token hvariable">t</span><span class="token punctuation">,</span> <span class="token hvariable">b</span> <span class="token operator">&gt;</span> <span class="token hvariable">h</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- sort [3, 1, 4, 2]</span></span>
<span class="line"><span class="token comment">-- h = 3, t = [1, 4, 2]</span></span>
<span class="line"><span class="token comment">-- 왼쪽 = [1, 2]</span></span>
<span class="line"><span class="token comment">-- 오른쪽 = [4]</span></span>
<span class="line"><span class="token comment">-- 최종 결과 = sort [1, 2] ++ [3] ++ sort [4]</span></span>
<span class="line"><span class="token comment">-- 재귀적으로 수행되어 [1, 2, 3, 4]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Illustrates the concision of Haskell</li></ul><p><strong>Insertion sort</strong></p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token comment">-- 삽입 함수</span></span>
<span class="line"><span class="token hvariable">insert</span> <span class="token hvariable">x</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">x</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token hvariable">insert</span> <span class="token hvariable">x</span> <span class="token punctuation">(</span><span class="token hvariable">y</span><span class="token operator">:</span><span class="token hvariable">ys</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;=</span> <span class="token hvariable">y</span>    <span class="token operator">=</span> <span class="token hvariable">x</span> <span class="token operator">:</span> <span class="token hvariable">y</span> <span class="token operator">:</span> <span class="token hvariable">ys</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token builtin">otherwise</span> <span class="token operator">=</span> <span class="token hvariable">y</span> <span class="token operator">:</span> <span class="token hvariable">insert</span> <span class="token hvariable">x</span> <span class="token hvariable">ys</span></span>
<span class="line"><span class="token comment">-- 전체 정렬 함수</span></span>
<span class="line"><span class="token hvariable">isort</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token hvariable">isort</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">insert</span> <span class="token hvariable">x</span> <span class="token punctuation">(</span><span class="token hvariable">isort</span> <span class="token hvariable">xs</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">-- isort [3, 1, 4, 2]</span></span>
<span class="line"><span class="token comment">-- = insert 3 (isort [1,4,2])</span></span>
<span class="line"><span class="token comment">-- = insert 3 (insert 1 (isort [4,2]))</span></span>
<span class="line"><span class="token comment">-- = insert 3 (insert 1 (insert 4 (isort [2])))</span></span>
<span class="line"><span class="token comment">-- = insert 3 (insert 1 (insert 4 (insert 2 [])))</span></span>
<span class="line"><span class="token comment">-- 순차적으로 정렬되어 [1,2,3,4]</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">{- [In scheme]</span>
<span class="line">(DEFINE (insert atm lst)</span>
<span class="line">  (COND</span>
<span class="line">    ((NULL? lst) (CONS atm &#39;()))</span>
<span class="line">    ((&lt; atm (CAR lst)) (CONS atm lst))</span>
<span class="line">    (ELSE (CONS (CAR lst) (insert atm (CDR lst))))))</span>
<span class="line"></span>
<span class="line">(DEFINE (sort lst)</span>
<span class="line">  (if (NULL? lst)</span>
<span class="line">    &#39;()</span>
<span class="line">    (insert (CAR lst) (sort (CDR lst))))) -}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>insert</code>: x를 정렬된 리스트에 올바른 위치에 삽입함. 빈 리스트면 <code>[x]</code>를 반환. 앞의 원소 y와 비교해서 x &lt;= y이면 x를 앞에 붙이고, 그렇지 않으면 y를 유지하고 나머지에 대해 재귀적으로 삽입</li><li><code>isort</code>: 입력 리스트를 왼쪽부터 하나씩 분해하면서 나머지를 먼저 정렬한 후, insert로 하나씩 앞에 끼워 넣는 방식 (재귀)</li></ul><p><strong>Merge sort</strong></p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">merge</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token hvariable">ys</span> <span class="token operator">=</span> <span class="token hvariable">ys</span></span>
<span class="line"><span class="token hvariable">merge</span> <span class="token hvariable">xs</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token hvariable">xs</span></span>
<span class="line"><span class="token hvariable">merge</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token hvariable">y</span><span class="token operator">:</span><span class="token hvariable">ys</span><span class="token punctuation">)</span> <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">if</span> <span class="token hvariable">x</span> <span class="token operator">&lt;=</span> <span class="token hvariable">y</span> <span class="token keyword">then</span> <span class="token hvariable">x</span> <span class="token operator">:</span> <span class="token hvariable">merge</span> <span class="token hvariable">xs</span> <span class="token punctuation">(</span><span class="token hvariable">y</span><span class="token operator">:</span><span class="token hvariable">ys</span><span class="token punctuation">)</span> <span class="token keyword">else</span> <span class="token hvariable">y</span> <span class="token operator">:</span> <span class="token hvariable">merge</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token hvariable">ys</span></span>
<span class="line"></span>
<span class="line"><span class="token hvariable">halve</span> <span class="token hvariable">xs</span> <span class="token operator">=</span> <span class="token builtin">splitAt</span> <span class="token punctuation">(</span><span class="token builtin">length</span> <span class="token hvariable">xs</span> <span class="token operator">\`div\`</span> <span class="token number">2</span><span class="token punctuation">)</span> <span class="token hvariable">xs</span></span>
<span class="line"></span>
<span class="line"><span class="token hvariable">msort</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token hvariable">msort</span> <span class="token punctuation">[</span><span class="token hvariable">x</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">x</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token hvariable">msort</span> <span class="token hvariable">xs</span> <span class="token operator">=</span> <span class="token hvariable">merge</span> <span class="token punctuation">(</span><span class="token hvariable">msort</span> <span class="token hvariable">ys</span><span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token hvariable">msort</span> <span class="token hvariable">zs</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">where</span> <span class="token punctuation">(</span><span class="token hvariable">ys</span><span class="token punctuation">,</span> <span class="token hvariable">zs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">halve</span> <span class="token hvariable">xs</span></span>
<span class="line"><span class="token comment">-- msort [4,1,5,2,6,3]</span></span>
<span class="line"><span class="token comment">-- halve: ([4,1,5],[2,6,3])</span></span>
<span class="line"><span class="token comment">-- 재귀적으로 msort 두 번 적용</span></span>
<span class="line"><span class="token comment">-- 결과: [1,2,3,4,5,6]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li><code>merge</code> 함수 – 두 정렬된 리스트를 병합: 두 리스트가 정렬된 상태로 들어오면, 앞에서부터 작은 값을 하나씩 뽑아서 새 리스트를 구성. x &lt;= y일 때 x가 먼저 오고, 아니라면 y가 먼저</li><li><code>halve</code> 함수 – 리스트를 반으로 나눔: <code>splitAt</code>은 리스트를 지정한 인덱스에서 둘로 나눔. <code>length xs \\</code>div\` 2\`를 이용해 반으로 쪼개기</li><li><code>msort</code> 함수 – 병합 정렬 전체 구현: 기저 조건으로 빈 리스트, 하나짜리 리스트는 정렬된 상태로 그대로 반환. 그렇지 않으면 리스트를 반으로 나누고, 양쪽을 재귀적으로 정렬한 뒤 merge함. <code>where</code> 구문으로 <code>ys</code>, <code>zs</code> 정의</li></ol><p><strong>Higher-order functions</strong></p><ul><li>Higher-order function: 함수를 인자로 받거나 함수를 결과로 반환하는 함수</li></ul><p><code>map</code>: 리스트의 각 원소에 함수를 적용하여 새로운 리스트를 만드는 함수</p><p><code>map</code>은 함수 f를 인자로 받는 함수이므로 고차 함수임</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">map</span> <span class="token punctuation">(</span><span class="token operator">+</span><span class="token number">1</span><span class="token punctuation">)</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">7</span><span class="token punctuation">]</span>  <span class="token comment">-- [2, 4, 6, 8]</span></span>
<span class="line"><span class="token comment">-- 1. 리스트 내포 (List Comprehension)</span></span>
<span class="line"><span class="token builtin">map</span> <span class="token hvariable">f</span> <span class="token hvariable">xs</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">f</span> <span class="token hvariable">x</span> <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token hvariable">xs</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- 2. 재귀 (Recursive Function)</span></span>
<span class="line"><span class="token builtin">map</span> <span class="token hvariable">f</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">map</span> <span class="token hvariable">f</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">f</span> <span class="token hvariable">x</span> <span class="token operator">:</span> <span class="token builtin">map</span> <span class="token hvariable">f</span> <span class="token hvariable">xs</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>foldr</code>: 리스트를 오른쪽에서 왼쪽으로 줄여나가는 함수 (right fold)</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">f [] = v</span>
<span class="line">f (x:xs) = x \`pred\` f xs</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>If it is an empty element, it returns a specific value v. Otherwise, pred is applied to element x, and f is applied to the remaining tail xs</li></ul><p>구문 형태: <code>foldr &lt;operator&gt; &lt;initial_value&gt; &lt;list&gt;</code></p><p>작동 방식: <code>foldr f v [x1, x2, x3]</code> = <code>x1 \\</code>f\` (x2 \`f\` (x3 \`f\` v))\`</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token comment">-- v = 0, pred = +</span></span>
<span class="line"><span class="token builtin">sum</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line"><span class="token builtin">sum</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">x</span> <span class="token operator">+</span> <span class="token builtin">sum</span> <span class="token hvariable">xs</span></span>
<span class="line"><span class="token builtin">sum</span> <span class="token operator">=</span> <span class="token builtin">foldr</span> <span class="token punctuation">(</span><span class="token operator">+</span><span class="token punctuation">)</span> <span class="token number">0</span></span>
<span class="line"><span class="token comment">-- v = 1, pred = *</span></span>
<span class="line"><span class="token builtin">product</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">1</span></span>
<span class="line"><span class="token builtin">product</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">x</span> <span class="token operator">*</span> <span class="token builtin">product</span> <span class="token hvariable">xs</span></span>
<span class="line"><span class="token builtin">product</span> <span class="token operator">=</span> <span class="token builtin">foldr</span> <span class="token punctuation">(</span><span class="token operator">*</span><span class="token punctuation">)</span> <span class="token number">1</span></span>
<span class="line"><span class="token comment">-- v = True, pred = &amp;&amp;</span></span>
<span class="line"><span class="token builtin">and</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token constant">True</span></span>
<span class="line"><span class="token builtin">and</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token hvariable">x</span> <span class="token operator">&amp;&amp;</span> <span class="token builtin">and</span> <span class="token hvariable">xs</span></span>
<span class="line"><span class="token builtin">and</span> <span class="token operator">=</span> <span class="token builtin">foldr</span> <span class="token punctuation">(</span><span class="token operator">&amp;&amp;</span><span class="token punctuation">)</span> <span class="token constant">True</span></span>
<span class="line"><span class="token comment">-- v = 0, pred = \\_ n -&gt; 1 + n</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">0</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token number">1</span> <span class="token operator">+</span> <span class="token builtin">length</span> <span class="token hvariable">xs</span></span>
<span class="line"><span class="token builtin">length</span> <span class="token operator">=</span> <span class="token builtin">foldr</span> <span class="token punctuation">(</span><span class="token operator">\\</span><span class="token hvariable">_</span> <span class="token hvariable">n</span> <span class="token operator">-&gt;</span> <span class="token number">1</span> <span class="token operator">+</span> <span class="token hvariable">n</span><span class="token punctuation">)</span> <span class="token number">0</span></span>
<span class="line"><span class="token comment">-- v = [], pred = \\x xs -&gt; xs ++ [x]</span></span>
<span class="line"><span class="token builtin">reverse</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">reverse</span> <span class="token punctuation">(</span><span class="token hvariable">x</span><span class="token operator">:</span><span class="token hvariable">xs</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token builtin">reverse</span> <span class="token hvariable">xs</span> <span class="token operator">++</span> <span class="token punctuation">[</span><span class="token hvariable">x</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token builtin">reverse</span> <span class="token operator">=</span> <span class="token builtin">foldr</span> <span class="token punctuation">(</span><span class="token operator">\\</span><span class="token hvariable">x</span> <span class="token hvariable">xs</span> <span class="token operator">-&gt;</span> <span class="token hvariable">xs</span> <span class="token operator">++</span> <span class="token punctuation">[</span><span class="token hvariable">x</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- length [10,20,30]</span></span>
<span class="line"><span class="token comment">-- = 1 + (1 + (1 + 0)) = 3</span></span>
<span class="line"><span class="token comment">-- reverse [1,2,3]</span></span>
<span class="line"><span class="token comment">-- = 3 : [] → [3]</span></span>
<span class="line"><span class="token comment">-- = 2 : [3] → [3,2]</span></span>
<span class="line"><span class="token comment">-- = 1 : [3,2] → [3,2,1]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>composition</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">f</span> <span class="token operator">.</span> <span class="token hvariable">g</span> <span class="token operator">=</span> <span class="token operator">\\</span><span class="token hvariable">x</span> <span class="token operator">-&gt;</span> <span class="token hvariable">f</span><span class="token punctuation">(</span><span class="token hvariable">g</span> <span class="token hvariable">x</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">-- \\x -&gt; expression: 익명 함수(anonymous function)</span></span>
<span class="line"><span class="token comment">-- f . g는 g를 먼저 적용하고, 그 결과를 f에 넘김</span></span>
<span class="line"><span class="token comment">-- 오른쪽부터 왼쪽으로 적용됨</span></span>
<span class="line"><span class="token comment">-- 예: odd = not . even</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>all</code>: 모든 요소가 조건을 만족하는가?</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">all</span> <span class="token hvariable">p</span> <span class="token hvariable">xs</span> <span class="token operator">=</span> <span class="token builtin">and</span> <span class="token punctuation">[</span><span class="token hvariable">p</span> <span class="token hvariable">x</span> <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token hvariable">xs</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- 리스트 xs의 각 원소에 함수 p를 적용해서 [Bool] 리스트를 만들고, and를 이용해 모든 값이 True인지 확인</span></span>
<span class="line"><span class="token builtin">all</span> <span class="token builtin">even</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">]</span>  <span class="token comment">-- True</span></span>
<span class="line"><span class="token builtin">all</span> <span class="token builtin">even</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">]</span>  <span class="token comment">-- False</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>any</code>: 하나라도 조건을 만족하는가?</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token builtin">any</span> <span class="token hvariable">p</span> <span class="token hvariable">xs</span> <span class="token operator">=</span> <span class="token builtin">or</span> <span class="token punctuation">[</span><span class="token hvariable">p</span> <span class="token hvariable">x</span> <span class="token operator">|</span> <span class="token hvariable">x</span> <span class="token operator">&lt;-</span> <span class="token hvariable">xs</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- 리스트 xs의 각 원소에 함수 p를 적용해서 [Bool] 리스트를 만들고, or를 이용해 하나라도 True인지 확인</span></span>
<span class="line"><span class="token builtin">any</span> <span class="token builtin">odd</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">]</span>  <span class="token comment">-- False</span></span>
<span class="line"><span class="token builtin">any</span> <span class="token builtin">odd</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">]</span>  <span class="token comment">-- True</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="lazy-evaluation" tabindex="-1"><a class="header-anchor" href="#lazy-evaluation"><span>Lazy Evaluation</span></a></h2><p>A language is strict if it requires all actual parameters to be fully evaluated</p><ul><li>Does not depend on the order in which the parameters are evaluated</li><li>예시: Scheme, ML, Java, Python</li><li><code>f(x + y)</code>를 호출하면, <code>x + y</code>는 무조건 먼저 계산됨</li><li>단점: 어떤 인자는 실제로 함수 내부에서 사용되지 않더라도 무조건 계산됨</li></ul><p>A language is nonstrict if it does not have the strict requirement</p><ul><li>인자가 사용될 때까지 평가를 미룸 (→ 필요할 때만 평가)</li><li>lazy evaluation을 지원하는 방식으로 구현 가능</li><li>예시: Haskell</li><li>Benefits: <ul><li>[1] Nonstrict languages are more efficient: Some evaluation is avoided (related to short-circuit evaluation)</li><li>[2] Lazy evaluation - Only compute those values that are necessary</li><li>Recall that in Scheme the parameters are fully evaluated before function call</li><li>Actual parameters are evaluated only once, even if the same actual parameter appears more than once</li><li>We can make infinite lists</li></ul></li><li>Infinite data structures: lazy evaluation(지연 평가) 덕분에 무한한 데이터 구조도 안전하게 다룰 수 있음</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">positives</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">0</span><span class="token operator">..</span><span class="token punctuation">]</span>          <span class="token comment">-- 0부터 시작하는 모든 자연수</span></span>
<span class="line"><span class="token hvariable">evens</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token operator">..</span><span class="token punctuation">]</span>           <span class="token comment">-- 2부터 시작해서 2씩 증가</span></span>
<span class="line"><span class="token hvariable">squares</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">n</span> <span class="token operator">*</span> <span class="token hvariable">n</span> <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">0</span><span class="token operator">..</span><span class="token punctuation">]</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token comment">-- Determining if 16 is a square number</span></span>
<span class="line"><span class="token hvariable">squares</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">n</span> <span class="token operator">*</span> <span class="token hvariable">n</span> <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">0</span><span class="token operator">..</span><span class="token punctuation">]</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token hvariable">member</span> <span class="token hvariable">squares</span> <span class="token number">16</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Member Revisited</strong></p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">member</span> <span class="token hvariable">b</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token constant">False</span></span>
<span class="line"><span class="token hvariable">member</span> <span class="token hvariable">b</span> <span class="token punctuation">(</span><span class="token hvariable">a</span><span class="token operator">:</span><span class="token hvariable">x</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token hvariable">a</span> <span class="token operator">==</span> <span class="token hvariable">b</span><span class="token punctuation">)</span> <span class="token operator">||</span> <span class="token hvariable">member</span> <span class="token hvariable">b</span> <span class="token hvariable">x</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>무한 리스트에서 특정 값이 존재하는지 안전하게 검사하는 방법: 리스트를 앞에서부터 순회하며, b와 같은 원소가 있으면 True 반환. 그러나 무한 리스트에 대해 사용하면 위험함 → 예: <code>member 5 [n*n | n &lt;- [0..]]</code>에서 5는 없으므로 끝없이 탐색함</p><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">member2</span> <span class="token hvariable">n</span> <span class="token punctuation">(</span><span class="token hvariable">m</span><span class="token operator">:</span><span class="token hvariable">x</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">m</span> <span class="token operator">&lt;</span> <span class="token hvariable">n</span>     <span class="token operator">=</span> <span class="token hvariable">member2</span> <span class="token hvariable">n</span> <span class="token hvariable">x</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token hvariable">m</span> <span class="token operator">==</span> <span class="token hvariable">n</span>    <span class="token operator">=</span> <span class="token constant">True</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token builtin">otherwise</span> <span class="token operator">=</span> <span class="token constant">False</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>리스트 <code>(m:x)</code>는 정렬된 상태라고 가정 (예: [0², 1², 2², ...])</li><li>m &lt; n이면 계속 탐색</li><li>m == n이면 True</li><li>m &gt; n이면 더 이상 찾을 필요 없음 → False 즉시 반환</li><li>불필요한 평가 없이 빠르게 종료 가능</li><li>무한 리스트에 대해서도 안전하게 동작</li></ul><div class="language-haskell line-numbers-mode" data-highlighter="prismjs" data-ext="haskell"><pre><code class="language-haskell"><span class="line"><span class="token hvariable">squares</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token hvariable">n</span> <span class="token operator">*</span> <span class="token hvariable">n</span> <span class="token operator">|</span> <span class="token hvariable">n</span> <span class="token operator">&lt;-</span> <span class="token punctuation">[</span><span class="token number">0</span><span class="token operator">..</span><span class="token punctuation">]</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token hvariable">member2</span> <span class="token number">16</span> <span class="token hvariable">squares</span>  <span class="token comment">-- True</span></span>
<span class="line"><span class="token hvariable">member2</span> <span class="token number">5</span> <span class="token hvariable">squares</span>   <span class="token comment">-- False (빠르게 종료)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="f" tabindex="-1"><a class="header-anchor" href="#f"><span>F#</span></a></h2><ul><li>Based on Ocaml, which is a descendant of ML and Haskell</li><li>Fundamentally a functional language, but with imperative features (mutable, loop) and supports OOP <ul><li>Has a full-featured IDE, an extensive library of utilities</li><li>Interoperates with other .NET languages</li><li>Free from Microsoft and supported by Visual Studio</li><li>Interoperability between C# and F# is quite easy</li></ul></li><li>Compared to C#: <ul><li>Simple to write code and easy to maintain</li><li>Immutability</li><li>Function itself is a first-class object</li><li>Supports lazy evaluation</li></ul></li></ul><p><strong>let binding</strong></p><p>값을 정의(바인딩)하거나 함수를 선언할 때 사용</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> square x <span class="token operator">=</span> x <span class="token operator">*</span> x  <span class="token comment">// function for square</span></span>
<span class="line"><span class="token keyword">let</span> output <span class="token operator">=</span> square <span class="token number">5</span>  <span class="token comment">// 25</span></span>
<span class="line"><span class="token keyword">let</span> a <span class="token operator">=</span> <span class="token number">7</span>              <span class="token comment">// 7</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Mutable function is possible</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token keyword">mutable</span> mutableX <span class="token operator">=</span> <span class="token number">5</span></span>
<span class="line">mutableX <span class="token operator">&lt;-</span> mutableX <span class="token operator">+</span> <span class="token number">1</span>  <span class="token comment">// 6, &lt;- is assignment operator</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>It should be carefully considered to use mutable because it breaks functional programming paradigm → Usually, it is possible to implement program without mutable</li><li>Similar to Haskell: Statically typed, strongly typed, type inferencing, pattern matching</li><li>Primitive types: <code>bool</code>, <code>byte</code>, <code>int</code>, <code>float</code>, <code>double</code>, <code>char</code>, <code>unit</code> (no value, 값이 없음)</li><li>Includes a variety of data types: Tuples, lists, discriminated unions, records, and mutable and immutable arrays</li></ul><p><strong>Tuple</strong></p><ul><li>Group of values of one or more types. 불변(immutable) 데이터 구조</li><li>Useful for getting multiple inputs and returning outputs</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">(</span><span class="token string">&quot;one&quot;</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> a<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Assessing each element</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>  <span class="token comment">// a = 1, b = 2, c = 3</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><code>fst</code>와 <code>snd</code>는 2-튜플 전용 함수</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> c <span class="token operator">=</span> fst <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>  <span class="token comment">// c = 1</span></span>
<span class="line"><span class="token keyword">let</span> d <span class="token operator">=</span> snd <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>  <span class="token comment">// d = 2</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>3개 이상의 튜플에서는 직접 패턴 매칭이 필요함</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> third <span class="token punctuation">(</span>_<span class="token punctuation">,</span> _<span class="token punctuation">,</span> c<span class="token punctuation">)</span> <span class="token operator">=</span> c  <span class="token comment">// Function that returns the third element</span></span>
<span class="line">third <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>          <span class="token comment">// 결과: 3</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Struct tuple</strong></p><ul><li>Value type tuple (&lt;-&gt; reference type)</li><li>Stored in the stack, not the heap (더 성능이 우수할 수 있음)</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> str <span class="token operator">=</span> <span class="token keyword">struct</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span>      <span class="token comment">// 선언</span></span>
<span class="line"><span class="token keyword">let</span> <span class="token keyword">struct</span> <span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token keyword">struct</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>  <span class="token comment">// a = 1, b = 2, 구조 분해</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>struct</code> 키워드를 튜플 앞에 붙여 선언</li><li>분해할 때도 반드시 <code>struct</code> 키워드 사용해야 함</li><li>Implicit conversion is not possible (struct tuple과 일반 tuple 간의 암묵적 변환은 불가능)</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token keyword">struct</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>    <span class="token comment">// 오류: 구조 분해는 struct로 해야 함</span></span>
<span class="line"><span class="token keyword">let</span> <span class="token keyword">struct</span> <span class="token punctuation">(</span>c<span class="token punctuation">,</span> d<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>    <span class="token comment">// 오류: 일반 튜플은 struct 분해 불가</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>When we need? <ul><li>Improve performance when the number of elements in the tuple to be used is large or individual elements have complex types</li><li>Interop with C#</li></ul></li><li>Supports generic sequences, whose values can be created with generators and through iteration <ul><li>from the .NET namespace <code>System.Collections.Generic.IEnumerable</code></li><li><code>seq&lt;&#39;T&gt;</code>는 .NET의 <code>System.Collections.Generic.IEnumerable&lt;T&gt;</code>의 F# 표현</li><li>즉, 일반화된 시퀀스 타입 → 리스트, 배열, 집합 등과 유사하지만 지연 평가(lazy evaluation)가 가능함</li></ul></li></ul><p><strong>List</strong></p><p>A List is an ordered, immutable collection of elements of the same type</p><ul><li>Internally implemented as a Singly linked list</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> x1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>               <span class="token comment">// empty list</span></span>
<span class="line"><span class="token keyword">let</span> x2 <span class="token operator">=</span> <span class="token punctuation">[</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token punctuation">]</span>    <span class="token comment">// list with elements 1, 2, and 3</span></span>
<span class="line"><span class="token keyword">let</span> x3 <span class="token operator">=</span> <span class="token punctuation">[</span> <span class="token number">1</span> <span class="token operator">..</span> <span class="token number">1000</span> <span class="token punctuation">]</span>   <span class="token comment">// List with integers from 1 to 1000 as elements</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// CONS → ::</span></span>
<span class="line"><span class="token keyword">let</span> x <span class="token operator">=</span> <span class="token number">0</span> <span class="token operator">::</span> <span class="token punctuation">[</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token punctuation">]</span>  <span class="token comment">// [ 0; 1; 2; 3; ]</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// LIST → @</span></span>
<span class="line"><span class="token keyword">let</span> x <span class="token operator">=</span> <span class="token punctuation">[</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token punctuation">]</span> @ <span class="token punctuation">[</span> <span class="token number">4</span><span class="token punctuation">;</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token number">6</span><span class="token punctuation">;</span> <span class="token punctuation">]</span>  <span class="token comment">// [ 1; 2; 3; 4; 5; 6; ] 리스트 연결 (append)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// CAR → Head</span></span>
<span class="line"><span class="token keyword">let</span> y <span class="token operator">=</span> x<span class="token punctuation">.</span>Head  <span class="token comment">// 1</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// CDR → Tail</span></span>
<span class="line"><span class="token keyword">let</span> y <span class="token operator">=</span> x<span class="token punctuation">.</span>Tail  <span class="token comment">// [ 2; 3; ]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Array</strong></p><ul><li>Fixed-sized collection of mutable elements of the same type</li><li>Supports fast random access. .NET의 <code>System.Array</code>에 기반함</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> x1 <span class="token operator">=</span> Array<span class="token punctuation">.</span>empty                    <span class="token comment">// empty array</span></span>
<span class="line"><span class="token keyword">let</span> x2 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token operator">|</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token operator">|</span><span class="token punctuation">]</span>               <span class="token comment">// Array with elements 1, 2, and 3</span></span>
<span class="line"><span class="token keyword">let</span> x3<span class="token punctuation">:</span> <span class="token class-name">int</span> array <span class="token operator">=</span> Array<span class="token punctuation">.</span>zeroCreate <span class="token number">10</span> <span class="token comment">// array with 10 zeros</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> x <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token operator">|</span> <span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token number">4</span><span class="token punctuation">;</span> <span class="token number">5</span><span class="token punctuation">;</span> <span class="token operator">|</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token keyword">let</span> ele0 <span class="token operator">=</span> array1<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span>     <span class="token comment">// a = 1</span></span>
<span class="line"><span class="token keyword">let</span> subx1 <span class="token operator">=</span> array1<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">.</span><span class="token number">.4</span><span class="token punctuation">]</span> <span class="token comment">// array2 = [| 3; 4; 5; |]</span></span>
<span class="line"><span class="token keyword">let</span> subx2 <span class="token operator">=</span> array1<span class="token punctuation">[</span><span class="token punctuation">.</span><span class="token number">.1</span><span class="token punctuation">]</span>  <span class="token comment">// array3 = [| 1; 2; |]  slicing</span></span>
<span class="line"><span class="token keyword">let</span> subx3 <span class="token operator">=</span> array1<span class="token punctuation">[</span><span class="token number">3</span><span class="token operator">..</span><span class="token punctuation">]</span>  <span class="token comment">// array4 = [| 4; 5; |]  slicing</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Slicing copy and return a new array (not change original array)</li></ul><p><strong>Sequences</strong></p><p>A collection of elements of the same type, which support lazy evaluation</p><ul><li>Generated with range expressions</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> x <span class="token operator">=</span> <span class="token computation-expression keyword">seq</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">.</span><span class="token number">.4</span><span class="token punctuation">}</span><span class="token punctuation">;</span><span class="token punctuation">;</span>   <span class="token comment">// generates seq [1; 2; 3; 4], ;; is used in interactive mode</span></span>
<span class="line"><span class="token keyword">let</span> y <span class="token operator">=</span> <span class="token computation-expression keyword">seq</span> <span class="token punctuation">{</span><span class="token number">0</span><span class="token punctuation">.</span><span class="token number">.10000000</span><span class="token punctuation">}</span><span class="token punctuation">;</span><span class="token punctuation">;</span>  <span class="token comment">// only the needed elements are generated</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Generation of sequence values is lazy</li></ul><table><thead><tr><th>항목</th><th>List</th><th>Array</th><th>Sequence (seq)</th></tr></thead><tbody><tr><td>가변성</td><td>불변 (Immutable)</td><td>가변 (Mutable)</td><td>불변 (읽기 전용)</td></tr><tr><td>평가</td><td>즉시 평가 (Eager)</td><td>즉시 평가 (Eager)</td><td>지연 평가 (Lazy)</td></tr><tr><td>구조</td><td>연결 리스트</td><td>연속된 메모리 배열</td><td>반복자 (IEnumerable) 기반</td></tr><tr><td>접근</td><td>앞쪽만 빠름</td><td>인덱스 접근 빠름 (O(1))</td><td>순차 접근만 가능</td></tr><tr><td>무한 지원</td><td>불가</td><td>불가</td><td>가능 (필요할 때만 생성됨)</td></tr></tbody></table><ul><li>Default stepsize is 1, but it can be any number</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> seq1 <span class="token operator">=</span> <span class="token computation-expression keyword">seq</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">.</span><span class="token number">.2</span><span class="token punctuation">.</span><span class="token number">.7</span><span class="token punctuation">}</span></span>
<span class="line"><span class="token comment">// Sets seq1 to [1; 3; 5; 7]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Iterated with a for-in construct</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> seq1 <span class="token operator">=</span> <span class="token computation-expression keyword">seq</span> <span class="token punctuation">{</span><span class="token number">0</span><span class="token punctuation">.</span><span class="token number">.3</span><span class="token punctuation">.</span><span class="token number">.11</span><span class="token punctuation">}</span><span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">for</span> value <span class="token keyword">in</span> seq1 <span class="token keyword">do</span> printfn <span class="token string">&quot;value = %d&quot;</span> value<span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// value = 0</span></span>
<span class="line"><span class="token comment">// value = 3</span></span>
<span class="line"><span class="token comment">// value = 6</span></span>
<span class="line"><span class="token comment">// value = 9</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Iterators – not lazy for lists and arrays (sequences are lazy)</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> cubes <span class="token operator">=</span> <span class="token computation-expression keyword">seq</span> <span class="token punctuation">{</span><span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token number">1</span><span class="token punctuation">.</span><span class="token number">.4</span> <span class="token operator">-&gt;</span> <span class="token punctuation">(</span>i<span class="token punctuation">,</span> i <span class="token operator">*</span> i <span class="token operator">*</span> i<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// Sets cubes to [(1, 1); (2, 8); (3, 27); (4, 64)]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Functions</strong></p><ul><li>If named, defined with <code>let</code></li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> x <span class="token operator">=</span> a <span class="token operator">/</span> b  <span class="token comment">// ← 매개변수 없는 함수처럼 작동</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>No difference between a name defined with <code>let</code> and a function without parameters</li><li>The extent of a function is defined by indentation. 함수 내부에서도 <code>let</code>을 중첩 사용 가능</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> f <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">let</span> pi <span class="token operator">=</span> <span class="token number">3.14159</span></span>
<span class="line">  <span class="token keyword">let</span> twoPi <span class="token operator">=</span> <span class="token number">2.0</span> <span class="token operator">*</span> pi<span class="token punctuation">;</span><span class="token punctuation">;</span>  <span class="token comment">// 2 instead of 2.0 causes error</span></span>
<span class="line">  twoPi<span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Does not coerce numeric values (수치 연산 시 정수/실수 타입 명확히 지정해야 함)</li><li>Names in functions can be outscoped, which ends their scope</li></ul><p><code>let</code>으로 같은 이름을 다시 정의하면 이전 변수의 스코프가 종료됨</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> x4 <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">let</span> x <span class="token operator">=</span> x <span class="token operator">*</span> x</span>
<span class="line">  <span class="token keyword">let</span> x <span class="token operator">=</span> x <span class="token operator">*</span> x</span>
<span class="line">  x<span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>The first <code>let</code> in the body of the function creates a new version of x; This terminates the scope of the parameter</li><li>The second <code>let</code> in the body creates another x, Terminating the scope of the second x</li><li>If lambda expressions, defined with <code>fun</code></li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">fun</span> a b <span class="token operator">-&gt;</span> a <span class="token operator">/</span> b</span>
<span class="line"><span class="token keyword">fun</span> x y <span class="token operator">-&gt;</span> <span class="token keyword">let</span> swap <span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token punctuation">(</span>b<span class="token punctuation">,</span> a<span class="token punctuation">)</span> <span class="token keyword">in</span> swap <span class="token punctuation">(</span>x<span class="token punctuation">,</span> y<span class="token punctuation">)</span>  <span class="token comment">// 람다 안에서 내부 함수 정의</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>fun a b -&gt; expr</code>는 익명 함수이며, <code>let</code> 없이도 정의 가능</li><li>람다 내부에서도 <code>let</code>으로 지역 함수 정의 가능</li><li>If a function is recursive, its definition must include the <code>rec</code> reserved word</li></ul><p>F#에서 기본적으로 함수 이름은 내부에서 접근 불가 (자기 참조 금지)</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token keyword">rec</span> factorial x <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">if</span> x <span class="token operator">&lt;=</span> <span class="token number">1</span> <span class="token keyword">then</span> <span class="token number">1</span></span>
<span class="line">  <span class="token keyword">else</span> n <span class="token operator">*</span> <span class="token function">factorial</span><span class="token punctuation">(</span>n − <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>재귀 함수와 패턴 매칭</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token keyword">rec</span> factorial n <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">match</span> n <span class="token keyword">with</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token number">0</span> <span class="token operator">-&gt;</span> <span class="token number">1</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token number">1</span> <span class="token operator">-&gt;</span> <span class="token number">1</span></span>
<span class="line">  <span class="token operator">|</span> _ <span class="token operator">-&gt;</span> n <span class="token operator">*</span> factorial <span class="token punctuation">(</span>n <span class="token operator">-</span> <span class="token number">1</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>rec</code> 필수 → 재귀 가능</li><li><code>match ... with</code> → 다중 분기 시 가독성 및 안정성 향상</li><li><code>_</code> → 기본값 또는 &quot;그 외 모든 경우&quot; 처리</li><li>Currying is supported. If a function has multiple arguments, it is automatically treated as currying</li></ul><p>F#은 기본적으로 함수에 인자가 여러 개 있어도 자동으로 커링 처리함</p><p>튜플 <code>(a, b)</code>을 하나의 인자로 받으면 커링이 되지 않음</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> add <span class="token punctuation">(</span>a<span class="token punctuation">:</span><span class="token class-name">int</span><span class="token punctuation">)</span> <span class="token punctuation">(</span>b<span class="token punctuation">:</span><span class="token class-name">int</span><span class="token punctuation">)</span> <span class="token operator">=</span> a <span class="token operator">+</span> b</span>
<span class="line"><span class="token keyword">let</span> add5 <span class="token operator">=</span> add <span class="token number">5</span></span>
<span class="line"><span class="token keyword">let</span> result <span class="token operator">=</span> add5 <span class="token number">3</span>  <span class="token comment">// 8</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// If want to prevent currying - Use tuple</span></span>
<span class="line"><span class="token keyword">let</span> add1 a b <span class="token operator">=</span> a <span class="token operator">+</span> b</span>
<span class="line"><span class="token keyword">let</span> add2 <span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span> <span class="token operator">=</span> a <span class="token operator">+</span> b</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>inline</code></p><p><code>inline</code> 키워드와 다형성(polymorphism)을 이용해 함수 오버로딩을 흉내낼 수 있음</p><p>컴파일 타임에 함수 본문이 직접 삽입(inlined)됨. 덕분에 제네릭 타입 연산자 (+, * 등)가 타입 추론을 통해 다양한 타입에서 사용 가능해짐</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> add1 a b <span class="token operator">=</span> a <span class="token operator">+</span> b</span>
<span class="line"><span class="token keyword">let</span> result1 <span class="token operator">=</span> add1 <span class="token number">1</span> <span class="token number">2</span></span>
<span class="line"><span class="token keyword">let</span> result2 <span class="token operator">=</span> add1 <span class="token string">&quot;dog&quot;</span> <span class="token string">&quot;cat&quot;</span>  <span class="token comment">// error! 문자열 + 는 지원 안됨</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> <span class="token keyword">inline</span> add2 a b <span class="token operator">=</span> a <span class="token operator">+</span> b</span>
<span class="line"><span class="token keyword">let</span> result3 <span class="token operator">=</span> add2 <span class="token number">1</span> <span class="token number">2</span>          <span class="token comment">// 3</span></span>
<span class="line"><span class="token keyword">let</span> result4 <span class="token operator">=</span> add2 <span class="token string">&quot;dog&quot;</span> <span class="token string">&quot;cat&quot;</span>  <span class="token comment">// &quot;dogcat&quot; 타입 추론 기반 연산 허용 → 오버로딩처럼 동작 가능</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Can mimic function overloading</li></ul><p><strong>Functions (collection)</strong></p><p><code>iter</code>: 주어진 함수를 리스트의 각 요소에 대해 실행 (반환값 없음)</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> l1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">]</span></span>
<span class="line">List<span class="token punctuation">.</span>iter <span class="token punctuation">(</span><span class="token keyword">fun</span> x <span class="token operator">-&gt;</span> printf <span class="token string">&quot;%d &quot;</span> x<span class="token punctuation">)</span> l1</span>
<span class="line">List<span class="token punctuation">.</span>iteri <span class="token punctuation">(</span><span class="token keyword">fun</span> i x <span class="token operator">-&gt;</span> printfn <span class="token string">&quot;Index %d: %d &quot;</span> i x<span class="token punctuation">)</span> l1</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>map</code>: 리스트의 각 요소에 함수를 적용하고, 그 결과를 새 리스트로 반환</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> l1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token keyword">let</span> r1 <span class="token operator">=</span> List<span class="token punctuation">.</span>map <span class="token punctuation">(</span><span class="token keyword">fun</span> x <span class="token operator">-&gt;</span> x <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span> l1   <span class="token comment">// [2; 3; 4]</span></span>
<span class="line"><span class="token keyword">let</span> r2 <span class="token operator">=</span> List<span class="token punctuation">.</span>mapi <span class="token punctuation">(</span><span class="token keyword">fun</span> i x <span class="token operator">-&gt;</span> x <span class="token operator">+</span> i<span class="token punctuation">)</span> l1 <span class="token comment">// [1; 3; 5]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>filter</code>: 주어진 조건 함수(pred)를 각 요소에 적용하고, 결과가 true인 요소만 추출</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> l1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token number">4</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token keyword">let</span> evenList <span class="token operator">=</span> List<span class="token punctuation">.</span>filter <span class="token punctuation">(</span><span class="token keyword">fun</span> x <span class="token operator">-&gt;</span> x <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">)</span> l1  <span class="token comment">// [2; 4]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>fold</code>: 리스트의 각 요소를 누적자(acc)와 함께 처리하여 최종 결과 계산</p><ul><li>Results from the previous element are accumulated and applied. Need accumulator (need to set initial)</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> sum list <span class="token operator">=</span> List<span class="token punctuation">.</span>fold <span class="token punctuation">(</span><span class="token keyword">fun</span> acc x <span class="token operator">-&gt;</span> acc <span class="token operator">+</span> x<span class="token punctuation">)</span> <span class="token number">0</span> list</span>
<span class="line"><span class="token keyword">let</span> r1 <span class="token operator">=</span> sum <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span><span class="token punctuation">]</span>  <span class="token comment">// 6 (순서: ((0 + 1) + 2) + 3)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> reverse list <span class="token operator">=</span> List<span class="token punctuation">.</span>fold <span class="token punctuation">(</span><span class="token keyword">fun</span> acc x <span class="token operator">-&gt;</span> x<span class="token operator">::</span>acc<span class="token punctuation">)</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> list</span>
<span class="line"><span class="token keyword">let</span> r2 <span class="token operator">=</span> reverse <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span><span class="token punctuation">]</span>  <span class="token comment">// [3; 2; 1]</span></span>
<span class="line"><span class="token comment">// 순서: [] |&gt; 1::[] → [1] |&gt; 2::[1] → [2;1] |&gt; 3::[2;1] → [3;2;1]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>do</code>: When we need to do it without saving the result. 반환값은 무시됨 (unit으로 처리됨)</p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">do</span> printf <span class="token string">&quot;Hello World&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>Function Composition</strong></p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> negate x <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">1</span> <span class="token operator">*</span> x</span>
<span class="line"><span class="token keyword">let</span> square x <span class="token operator">=</span> x <span class="token operator">*</span> x</span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> temp <span class="token operator">=</span> square <span class="token number">3</span>    <span class="token comment">// 9</span></span>
<span class="line"><span class="token keyword">let</span> result <span class="token operator">=</span> negate temp  <span class="token comment">// -9</span></span>
<span class="line"><span class="token comment">// Or:</span></span>
<span class="line"><span class="token keyword">let</span> result <span class="token operator">=</span> negate <span class="token punctuation">(</span>square <span class="token number">3</span><span class="token punctuation">)</span>  <span class="token comment">// -9</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Composition (<code>&gt;&gt;</code>): 함수 조합 연산자</li><li>Builds a function that applies its left operand to a given parameter (a function) and then passes the result returned from the function to its right operand (another function)</li><li>The F# expression <code>(f &gt;&gt; g) x</code> is equivalent to the mathematical expression <code>g(f(x))</code></li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> composed <span class="token operator">=</span> square <span class="token operator">&gt;&gt;</span> negate</span>
<span class="line"><span class="token keyword">let</span> result <span class="token operator">=</span> composed <span class="token number">3</span>  <span class="token comment">// 결과: -9 (square 3 = 9 → negate 9 = -9)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> <span class="token keyword">inline</span> <span class="token punctuation">(</span><span class="token operator">&gt;&gt;</span><span class="token punctuation">)</span> f g x <span class="token operator">=</span> g <span class="token punctuation">(</span>f x<span class="token punctuation">)</span>  <span class="token comment">// Forward composition</span></span>
<span class="line"><span class="token keyword">let</span> <span class="token keyword">inline</span> <span class="token punctuation">(</span><span class="token operator">&lt;&lt;</span><span class="token punctuation">)</span> f g x <span class="token operator">=</span> f <span class="token punctuation">(</span>g x<span class="token punctuation">)</span>  <span class="token comment">// Reverse composition</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> negateSquare <span class="token operator">=</span> square <span class="token operator">&gt;&gt;</span> negate</span>
<span class="line"><span class="token keyword">let</span> result <span class="token operator">=</span> negateSquare <span class="token number">3</span>  <span class="token comment">// -9</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Pipeline</strong></p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> even values <span class="token operator">=</span> List<span class="token punctuation">.</span>filter <span class="token punctuation">(</span><span class="token keyword">fun</span> n <span class="token operator">-&gt;</span> n <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">)</span> values</span>
<span class="line"><span class="token keyword">let</span> mulFive values <span class="token operator">=</span> List<span class="token punctuation">.</span>map <span class="token punctuation">(</span><span class="token keyword">fun</span> n <span class="token operator">-&gt;</span> <span class="token number">5</span> <span class="token operator">*</span> n<span class="token punctuation">)</span> values</span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> combine1 values <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">let</span> evens <span class="token operator">=</span> List<span class="token punctuation">.</span>filter <span class="token punctuation">(</span><span class="token keyword">fun</span> n <span class="token operator">-&gt;</span> n <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">)</span> values</span>
<span class="line">  <span class="token keyword">let</span> mulFives <span class="token operator">=</span> List<span class="token punctuation">.</span>map <span class="token punctuation">(</span><span class="token keyword">fun</span> n <span class="token operator">-&gt;</span> <span class="token number">5</span> <span class="token operator">*</span> n<span class="token punctuation">)</span> evens</span>
<span class="line">  mulFives</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>In fact, if it is clear that the previous result value is to be passed to value name in the next function, this way would be an unnecessary syntax</li><li>Pipeline (<code>|&gt;</code>): A binary operator that sends the value of its left operand to the last parameter of the call (the right operand)</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token keyword">inline</span> <span class="token punctuation">(</span><span class="token operator">|&gt;</span><span class="token punctuation">)</span> x f <span class="token operator">=</span> f x</span>
<span class="line"><span class="token keyword">let</span> <span class="token keyword">inline</span> <span class="token punctuation">(</span><span class="token operator">&lt;|</span><span class="token punctuation">)</span> f x <span class="token operator">=</span> f x</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Used to chain function calls together</li></ul><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> myNums <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">;</span> <span class="token number">2</span><span class="token punctuation">;</span> <span class="token number">3</span><span class="token punctuation">;</span> <span class="token number">4</span><span class="token punctuation">;</span> <span class="token number">5</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token keyword">let</span> evensTimesFive <span class="token operator">=</span> myNums</span>
<span class="line">  <span class="token operator">|&gt;</span> List<span class="token punctuation">.</span>filter <span class="token punctuation">(</span><span class="token keyword">fun</span> n <span class="token operator">-&gt;</span> n <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token operator">|&gt;</span> List<span class="token punctuation">.</span>map <span class="token punctuation">(</span><span class="token keyword">fun</span> n <span class="token operator">-&gt;</span> <span class="token number">5</span> <span class="token operator">*</span> n<span class="token punctuation">)</span></span>
<span class="line"><span class="token comment">// The return value is [10; 20]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Insert sort</strong></p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token keyword">rec</span> insert n ls <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">match</span> ls <span class="token keyword">with</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">-&gt;</span> <span class="token punctuation">[</span>n<span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">|</span> x<span class="token operator">::</span>xs <span class="token operator">-&gt;</span></span>
<span class="line">    <span class="token keyword">if</span> n <span class="token operator">&gt;</span> x <span class="token keyword">then</span> x <span class="token operator">::</span> insert n xs</span>
<span class="line">    <span class="token keyword">else</span> n <span class="token operator">::</span> ls<span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">let</span> <span class="token keyword">rec</span> insertSort ls <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">match</span> ls <span class="token keyword">with</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">-&gt;</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">|</span> x<span class="token operator">::</span>xs <span class="token operator">-&gt;</span> insert x <span class="token punctuation">(</span>insertSort xs<span class="token punctuation">)</span><span class="token punctuation">;</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// insertSort [3; 1; 4; 2];;</span></span>
<span class="line"><span class="token comment">// 결과: [1; 2; 3; 4]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Quicksort</strong></p><div class="language-fsharp line-numbers-mode" data-highlighter="prismjs" data-ext="fs"><pre><code class="language-fsharp"><span class="line"><span class="token keyword">let</span> <span class="token keyword">rec</span> quicksort list <span class="token operator">=</span></span>
<span class="line">  <span class="token keyword">match</span> list <span class="token keyword">with</span></span>
<span class="line">  <span class="token operator">|</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token operator">-&gt;</span> <span class="token punctuation">[</span><span class="token punctuation">]</span></span>
<span class="line">  <span class="token operator">|</span> firstElem<span class="token operator">::</span>otherElements <span class="token operator">-&gt;</span></span>
<span class="line">    <span class="token keyword">let</span> smallerElements <span class="token operator">=</span></span>
<span class="line">      otherElements</span>
<span class="line">      <span class="token operator">|&gt;</span> List<span class="token punctuation">.</span>filter <span class="token punctuation">(</span><span class="token keyword">fun</span> e <span class="token operator">-&gt;</span> e <span class="token operator">&lt;</span> firstElem<span class="token punctuation">)</span></span>
<span class="line">      <span class="token operator">|&gt;</span> quicksort</span>
<span class="line">    <span class="token keyword">let</span> largerElements <span class="token operator">=</span></span>
<span class="line">      otherElements</span>
<span class="line">      <span class="token operator">|&gt;</span> List<span class="token punctuation">.</span>filter <span class="token punctuation">(</span><span class="token keyword">fun</span> e <span class="token operator">-&gt;</span> e <span class="token operator">&gt;=</span> firstElem<span class="token punctuation">)</span></span>
<span class="line">      <span class="token operator">|&gt;</span> quicksort</span>
<span class="line">    smallerElements @ <span class="token punctuation">[</span>firstElem<span class="token punctuation">]</span> @ largerElements</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>부분</th><th>의미</th></tr></thead><tbody><tr><td><code>[]</code></td><td>입력 리스트가 빈 경우 종료조건</td></tr><tr><td><code>firstElem::otherElements</code></td><td>리스트를 피벗과 나머지로 분해</td></tr><tr><td><code>List.filter (fun e -&gt; e &lt; firstElem)</code></td><td>피벗보다 작은 원소 추출</td></tr><tr><td><code>List.filter (fun e -&gt; e &gt;= firstElem)</code></td><td>피벗보다 크거나 같은 원소 추출</td></tr><tr><td><code>|&gt; quicksort</code></td><td>재귀 호출, 각 부분을 정렬</td></tr><tr><td><code>@</code></td><td>리스트 결합 (좌: 작은 원소들 + 피벗 + 우: 큰 원소들)</td></tr></tbody></table><p><strong>Why F# is Interesting</strong></p><ul><li>It builds on previous functional languages (ML, Haskell, OCaml 등 기존 함수형 언어들의 이론적/실용적 기반 위에 설계됨)</li><li>It supports virtually all programming methodologies in widespread use today (함수형뿐 아니라 명령형, 객체지향, 데이터 흐름 기반 프로그래밍 등 여러 방식의 개발을 모두 지원함)</li><li>It is the first functional language that is designed for interoperability with other widely used languages (널리 사용되는 언어(C#, VB.NET 등)들과의 .NET 기반 상호운용성이 뛰어남. 즉, F# 코드와 C# 코드를 섞어서 사용할 수 있음)</li><li>At its release, it had an elaborate and well developed IDE and library of utility software (Visual Studio IDE 및 다양한 유틸리티 라이브러리와 함께 출시되어 실무에 바로 사용할 수 있는 환경을 제공함)</li></ul><h2 id="support-for-functional-programming-in-primarily-imperative-languages" tabindex="-1"><a class="header-anchor" href="#support-for-functional-programming-in-primarily-imperative-languages"><span>Support for Functional Programming in Primarily Imperative Languages</span></a></h2><ul><li>Support for functional programming is increasingly creeping into imperative languages <ul><li>예시: 람다 표현식, 불변 변수, 스트림 API 등은 FP의 개념을 차용한 것임</li></ul></li><li>The most important restriction: Lack of support for higher-order functions <ul><li>고차 함수란, 함수를 인자로 받거나 함수로 반환하는 함수를 의미</li><li>이 제약 때문에 진정한 함수형 프로그래밍 스타일을 구현하기 어렵다는 한계가 있음</li></ul></li><li>Although modern imperative languages support many functional features, they still primarily rely on mutable state and side effects</li></ul><p><strong>Anonymous functions (lambda expressions)</strong></p><p>함수에 이름을 붙이지 않고 정의하는 방식 → 일회성 사용이나 고차 함수 인자로 넘길 때 유용함</p><ul><li>JavaScript: leave the name out of a function definition</li></ul><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">function</span> <span class="token function">name</span> <span class="token punctuation">(</span><span class="token parameter">formal<span class="token operator">-</span>parameters</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  body</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">const</span> <span class="token function-variable function">square</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">x</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> x <span class="token operator">*</span> x<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// function(x) { return x * x; } ← 이름이 없는 함수 정의</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>C#: <code>(input-parameters) =&gt; expression</code></p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token comment">// i =&gt; (i % 2) == 0 (returns true or false depending on whether the parameter is even or odd)</span></span>
<span class="line"><span class="token class-name">List<span class="token punctuation">&lt;</span><span class="token keyword">int</span><span class="token punctuation">&gt;</span></span> numbers <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">List<span class="token punctuation">&lt;</span><span class="token keyword">int</span><span class="token punctuation">&gt;</span></span> <span class="token punctuation">{</span> <span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span> <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name"><span class="token keyword">var</span></span> evenNumbers <span class="token operator">=</span> numbers<span class="token punctuation">.</span><span class="token function">Where</span><span class="token punctuation">(</span>i <span class="token operator">=&gt;</span> i <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ToList</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">// 결과: [2, 4]</span></span>
<span class="line"><span class="token comment">// 여기서 Where는 고차 함수 (함수를 인자로 받는 함수), i =&gt; i % 2 == 0는 익명 함수 (람다)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Python: <code>lambda 매개변수들 : 표현식</code></li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line">f <span class="token operator">=</span> <span class="token keyword">lambda</span> a<span class="token punctuation">,</span> b<span class="token punctuation">:</span> <span class="token number">2</span> <span class="token operator">*</span> a <span class="token operator">-</span> b</span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span>f<span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 출력: 5</span></span>
<span class="line"></span>
<span class="line">nums <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span></span>
<span class="line">squares <span class="token operator">=</span> <span class="token builtin">list</span><span class="token punctuation">(</span><span class="token builtin">map</span><span class="token punctuation">(</span><span class="token keyword">lambda</span> x<span class="token punctuation">:</span> x <span class="token operator">*</span> x<span class="token punctuation">,</span> nums<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span>squares<span class="token punctuation">)</span>  <span class="token comment"># 출력: [1, 4, 9, 16]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Python supports the higher-order functions <code>filter</code> and <code>map</code> (often use lambda expressions as their first parameters) <ul><li><code>filter(function, iterable)</code>: 주어진 함수의 조건을 만족하는 요소만 남김</li></ul></li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token builtin">list</span><span class="token punctuation">(</span><span class="token builtin">filter</span><span class="token punctuation">(</span><span class="token keyword">lambda</span> x<span class="token punctuation">:</span> x <span class="token operator">%</span> <span class="token number">2</span> <span class="token operator">==</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment"># Returns [2, 4]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>map</code>: iterable의 모든 요소에 함수를 적용한 결과를 반환</li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token builtin">map</span><span class="token punctuation">(</span><span class="token keyword">lambda</span> x <span class="token punctuation">:</span> x <span class="token operator">**</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">,</span> <span class="token number">8</span><span class="token punctuation">]</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token comment"># Returns [8, 64, 216, 512]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>이런 고차 함수는 함수를 값처럼 다룰 수 있는 함수형 프로그래밍의 특징</p><ul><li>Python supports partial function applications: 여러 개의 인자를 받는 함수 중 일부 인자를 미리 고정해 놓고, 나머지 인자만 나중에 받아서 호출하는 방식</li><li>There are libraries for functional programming: <code>functools</code>, <code>itertools</code>, <code>operator</code></li></ul><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code class="language-python"><span class="line"><span class="token keyword">from</span> functools <span class="token keyword">import</span> partial</span>
<span class="line"></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">add</span> <span class="token punctuation">(</span>x<span class="token punctuation">,</span> y<span class="token punctuation">,</span> z<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token keyword">return</span> x <span class="token operator">+</span> y <span class="token operator">+</span> z</span>
<span class="line"></span>
<span class="line">add5 <span class="token operator">=</span> partial<span class="token punctuation">(</span>add<span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span></span>
<span class="line">add5<span class="token punctuation">(</span><span class="token number">15</span><span class="token punctuation">)</span>  <span class="token comment"># return 20</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">from</span> operator <span class="token keyword">import</span> add</span>
<span class="line">add5 <span class="token operator">=</span> partial<span class="token punctuation">(</span>add<span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span></span>
<span class="line">add5<span class="token punctuation">(</span><span class="token number">15</span><span class="token punctuation">)</span>  <span class="token comment"># return 20</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">multiply</span><span class="token punctuation">(</span>x<span class="token punctuation">,</span> y<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token keyword">return</span> x <span class="token operator">*</span> y</span>
<span class="line"></span>
<span class="line">double <span class="token operator">=</span> partial<span class="token punctuation">(</span>multiply<span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>  <span class="token comment"># x를 2로 고정 (2배 함수)</span></span>
<span class="line">numbers <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span></span>
<span class="line">doubled <span class="token operator">=</span> <span class="token builtin">list</span><span class="token punctuation">(</span><span class="token builtin">map</span><span class="token punctuation">(</span>double<span class="token punctuation">,</span> numbers<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># [2, 4, 6, 8]</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span>doubled<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">strings <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;apple&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;banana&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;kiwi&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;grape&#39;</span><span class="token punctuation">]</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">sorted</span><span class="token punctuation">(</span>strings<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># [&#39;apple&#39;, &#39;banana&#39;, &#39;grape&#39;, &#39;kiwi&#39;]</span></span>
<span class="line"></span>
<span class="line">sort_by_length <span class="token operator">=</span> partial<span class="token punctuation">(</span><span class="token builtin">sorted</span><span class="token punctuation">,</span> key<span class="token operator">=</span><span class="token builtin">len</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">print</span><span class="token punctuation">(</span>sort_by_length<span class="token punctuation">(</span>strings<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># [&#39;kiwi&#39;, &#39;apple&#39;, &#39;grape&#39;, &#39;banana&#39;]</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>함수</th><th>설명</th><th>partial 활용</th></tr></thead><tbody><tr><td><code>map</code></td><td>각 요소에 함수 적용</td><td>인자 일부를 고정한 함수 전달</td></tr><tr><td><code>sorted</code></td><td>정렬 기준을 정함</td><td>key 인자를 고정</td></tr></tbody></table><p><strong>Ruby Blocks</strong></p><ul><li>Are effectively subprograms that are sent to methods, which makes the method a higher order subprogram</li><li>Ruby에서는 메서드가 block을 받으면, 그 block을 실행할 수 있음. 즉, 해당 메서드는 고차 함수(higher-order function)로 작동</li><li>We can create blocks with <code>{ }</code> or <code>do ~ end</code>. Block can be passed to method</li></ul><div class="language-ruby line-numbers-mode" data-highlighter="prismjs" data-ext="rb"><pre><code class="language-ruby"><span class="line"><span class="token number">3.</span>times <span class="token punctuation">{</span> <span class="token operator">|</span>i<span class="token operator">|</span> puts i <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token number">3.</span>times <span class="token keyword">do</span> <span class="token operator">|</span>i<span class="token operator">|</span></span>
<span class="line">  x <span class="token operator">=</span> i <span class="token operator">*</span> <span class="token number">2</span></span>
<span class="line">  p x</span>
<span class="line"><span class="token keyword">end</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위 코드에서 <code>times</code> 메서드는 블록을 받아서, i를 0부터 2까지 넘겨주고, 블록 내 코드를 실행</p><ul><li>Block을 사용하는 이유: 반복 제어를 간결하게 처리, 콜백 처리</li></ul><div class="language-ruby line-numbers-mode" data-highlighter="prismjs" data-ext="rb"><pre><code class="language-ruby"><span class="line"><span class="token keyword">def</span> <span class="token method-definition"><span class="token function">custom_each</span></span><span class="token punctuation">(</span>array<span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">for</span> item <span class="token keyword">in</span> array</span>
<span class="line">    <span class="token keyword">yield</span><span class="token punctuation">(</span>item<span class="token punctuation">)</span>  <span class="token comment"># 넘겨받은 block 실행</span></span>
<span class="line">  <span class="token keyword">end</span></span>
<span class="line"><span class="token keyword">end</span></span>
<span class="line"></span>
<span class="line">custom_each<span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token keyword">do</span> <span class="token operator">|</span>n<span class="token operator">|</span></span>
<span class="line">  puts n <span class="token operator">*</span> <span class="token number">10</span></span>
<span class="line"><span class="token keyword">end</span></span>
<span class="line"><span class="token comment"># 출력: 10, 20, 30</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>여기서 <code>yield</code>는 메서드 안에서 block을 호출하는 키워드. block은 메서드 외부에서 정의되지만, 마치 메서드 안에 있는 것처럼 실행</p><p>A block can be converted to a subprogram object with <code>lambda</code></p><div class="language-ruby line-numbers-mode" data-highlighter="prismjs" data-ext="rb"><pre><code class="language-ruby"><span class="line">times <span class="token operator">=</span> lambda <span class="token punctuation">{</span><span class="token operator">|</span>a<span class="token punctuation">,</span> b<span class="token operator">|</span> a <span class="token operator">*</span> b<span class="token punctuation">}</span></span>
<span class="line">x <span class="token operator">=</span> times<span class="token punctuation">.</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">)</span>  <span class="token comment"># sets x to 12</span></span>
<span class="line"></span>
<span class="line">times5 <span class="token operator">=</span> times<span class="token punctuation">.</span>curry<span class="token punctuation">.</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span>  <span class="token comment"># 첫 번째 인자를 5로 고정한 새로운 함수</span></span>
<span class="line">x5 <span class="token operator">=</span> times5<span class="token punctuation">.</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>           <span class="token comment"># sets x5 to 15 (두 번째 인자만 주면 결과 계산됨)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="comparing-functional-and-imperative-languages" tabindex="-1"><a class="header-anchor" href="#comparing-functional-and-imperative-languages"><span>Comparing Functional and Imperative Languages</span></a></h2><ul><li>Imperative Languages: <ul><li>Complex semantics (상태 변화, 제어 흐름 중심)</li><li>Complex syntax (반복문, 대입문, 코드 블록 등)</li><li>Efficient execution (일반적으로 더 효율적임)</li><li>Concurrency is programmer designed (프로그래머가 직접 병렬 처리 설계)</li><li>가변 상태(mutable state) 사용</li><li>부수 효과 많음 (대입, 입출력 등)</li></ul></li><li>Functional Languages: <ul><li>Simple semantics (상태 없는 계산, 표현식 중심)</li><li>Simple syntax (함수 중심, 표현식 기반)</li><li>Less efficient execution (상대적으로 덜 효율적임 (불변성, 재귀 등으로 인해))</li><li>Programs can automatically be made concurrent (자동 병렬화 가능성이 높음)</li><li>불변 상태(immutable state) 지향</li><li>부수 효과를 피함 (순수 함수 사용)</li></ul></li></ul><h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary"><span>Summary</span></a></h2><ul><li>Functional programming languages use function application, conditional expressions, recursion, and functional forms to control program execution</li><li>Lisp began as a purely functional language and later included imperative features</li><li>Scheme is a relatively simple dialect of Lisp that uses static scoping exclusively</li><li>Common Lisp is a large Lisp-based language</li><li>ML is a static-scoped and strongly typed functional language that uses type inference</li><li>Haskell is a lazy functional language supporting infinite lists and set comprehension</li><li>F# is a .NET functional language that also supports imperative and object-oriented programming</li><li>Some primarily imperative languages now incorporate some support for functional programming</li><li>Purely functional languages have advantages over imperative alternatives, but still are not very widely used</li></ul>`,369))])}const k=e(i,[["render",r]]),m=JSON.parse('{"path":"/pl/13-FPL-(2).html","title":"13. FPL (2)","lang":"ko-KR","frontmatter":{"description":"13. FPL (2)","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"13. FPL (2)\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-11T17:33:49.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/pl/13-FPL-(2).html"}],["meta",{"property":"og:title","content":"13. FPL (2)"}],["meta",{"property":"og:description","content":"13. FPL (2)"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-11T17:33:49.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-11T17:33:49.000Z"}]]},"git":{"createdTime":1781199229000,"updatedTime":1781199229000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":2,"url":"https://github.com/kmbzn"}],"changelog":[{"hash":"93aaec14aeb23243f14a468bc423e7f688a54750","time":1781199229000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"docs: add Programming Languages section to sidebar and publish pl/ docs","coAuthors":[{"name":"kmbzn","email":"kmbzn24@gmail.com"}]}]},"filePathRelative":"pl/13-FPL-(2).md","autoDesc":true}');export{k as comp,m as data};
